// Customers API
export const customersAPI = {
  getAll: (config = {}) => api.get('/customers', config),
  getById: (id, config = {}) => api.get(`/customers/${id}`, config),
  create: (data, config = {}) => api.post('/customers', data, config),
  update: (id, data, config = {}) => api.put(`/customers/${id}`, data, config),
  delete: (id, config = {}) => api.delete(`/customers/${id}`, config),
  uploadPhoto: (id, formData, config = {}) => {
    const axiosConfig = {
      headers: {
        'content-type': 'multipart/form-data'
      },
      timeout: 120000, // 2 minutes default for photo uploads
      ...config
    }
    return api.post(`/customers/${id}/photo`, formData, axiosConfig)
  },
  updatePhoto: (id, formData, config = {}) => {
    const axiosConfig = {
      headers: {
        'content-type': 'multipart/form-data'
      },
      timeout: 120000, // 2 minutes default for photo uploads
      ...config
    }
    return api.put(`/customers/${id}/photo`, formData, axiosConfig)
  },
  deletePhoto: (id, config = {}) => api.delete(`/customers/${id}/photo`, config)
}

