import React, { useState } from 'react'
import { Search, Plus, Trash2, Calculator, CheckCircle } from 'lucide-react'

const BillingTest = () => {
  const [testItems, setTestItems] = useState([
    {
      id: 1,
      serviceName: 'Pan Services',
      subServiceName: 'New Pan Card',
      quantity: 1,
      unitPrice: 300,
      total: 300
    },
    {
      id: 2,
      serviceName: 'Aadhaar Services',
      subServiceName: 'Aadhaar Update',
      quantity: 2,
      unitPrice: 500,
      total: 1000
    }
  ])

  const [newItem, setNewItem] = useState({
    serviceName: '',
    subServiceName: '',
    quantity: 1,
    unitPrice: 0,
    total: 0
  })

  // Mock services data for testing
  const mockServices = [
    { _id: '1', serviceName: 'Pan Services', price: 300 },
    { _id: '2', serviceName: 'Aadhaar Services', price: 500 },
    { _id: '3', serviceName: 'Printing Services', price: 50 }
  ]

  const mockSubServices = [
    { _id: '1', subServiceName: 'New Pan Card', serviceId: '1', price: 300 },
    { _id: '2', subServiceName: 'Pan Correction', serviceId: '1', price: 200 },
    { _id: '3', subServiceName: 'Aadhaar Update', serviceId: '2', price: 500 },
    { _id: '4', subServiceName: 'Aadhaar Print', serviceId: '2', price: 100 }
  ]

  const handleServiceChange = (serviceId) => {
    const service = mockServices.find(s => s._id === serviceId)
    if (service) {
      setNewItem(prev => ({
        ...prev,
        serviceName: service.serviceName,
        unitPrice: service.price,
        total: prev.quantity * service.price
      }))
    }
  }

  const handleSubServiceChange = (subServiceId) => {
    const subService = mockSubServices.find(ss => ss._id === subServiceId)
    if (subService) {
      setNewItem(prev => ({
        ...prev,
        subServiceName: subService.subServiceName,
        unitPrice: subService.price,
        total: prev.quantity * subService.price
      }))
    }
  }

  const handleQuantityChange = (quantity) => {
    const newQuantity = parseInt(quantity) || 1
    setNewItem(prev => ({
      ...prev,
      quantity: newQuantity,
      total: newQuantity * prev.unitPrice
    }))
  }

  const handlePriceChange = (price) => {
    const newPrice = parseFloat(price) || 0
    setNewItem(prev => ({
      ...prev,
      unitPrice: newPrice,
      total: prev.quantity * newPrice
    }))
  }

  const addItem = () => {
    if (newItem.serviceName && newItem.subServiceName) {
      setTestItems(prev => [...prev, { ...newItem, id: Date.now() }])
      setNewItem({
        serviceName: '',
        subServiceName: '',
        quantity: 1,
        unitPrice: 0,
        total: 0
      })
    }
  }

  const removeItem = (id) => {
    setTestItems(prev => prev.filter(item => item.id !== id))
  }

  const calculateTotals = () => {
    const subtotal = testItems.reduce((sum, item) => sum + item.total, 0)
    const serviceCharges = 50 // Fixed service charge for testing
    const discount = 0
    const grandTotal = subtotal + serviceCharges - discount
    return { subtotal, serviceCharges, discount, grandTotal }
  }

  const totals = calculateTotals()

  return (
    <div className="p-6 max-w-6xl mx-auto">
      <div className="bg-white rounded-lg shadow-lg p-6">
        <div className="flex items-center gap-2 mb-6">
          <Calculator className="h-6 w-6 text-blue-600" />
          <h1 className="text-2xl font-bold text-gray-800">Billing System Test</h1>
        </div>

        {/* Test Form */}
        <div className="bg-gray-50 rounded-lg p-4 mb-6">
          <h2 className="text-lg font-semibold mb-4">Add New Item Test</h2>
          <div className="grid grid-cols-1 md:grid-cols-5 gap-4">
            <select
              value={mockServices.find(s => s.serviceName === newItem.serviceName)?._id || ''}
              onChange={(e) => handleServiceChange(e.target.value)}
              className="px-3 py-2 border border-gray-300 rounded-lg"
            >
              <option value="">Select Service</option>
              {mockServices.map(service => (
                <option key={service._id} value={service._id}>
                  {service.serviceName}
                </option>
              ))}
            </select>

            <select
              value={mockSubServices.find(ss => ss.subServiceName === newItem.subServiceName)?._id || ''}
              onChange={(e) => handleSubServiceChange(e.target.value)}
              className="px-3 py-2 border border-gray-300 rounded-lg"
            >
              <option value="">Select Sub-Service</option>
              {mockSubServices.map(subService => (
                <option key={subService._id} value={subService._id}>
                  {subService.subServiceName}
                </option>
              ))}
            </select>

            <input
              type="number"
              min="1"
              value={newItem.quantity}
              onChange={(e) => handleQuantityChange(e.target.value)}
              className="px-3 py-2 border border-gray-300 rounded-lg"
              placeholder="Quantity"
            />

            <input
              type="number"
              min="0"
              step="0.01"
              value={newItem.unitPrice}
              onChange={(e) => handlePriceChange(e.target.value)}
              className="px-3 py-2 border border-gray-300 rounded-lg"
              placeholder="Unit Price"
            />

            <button
              onClick={addItem}
              className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 flex items-center gap-2"
            >
              <Plus size={16} />
              Add Item
            </button>
          </div>

          {newItem.total > 0 && (
            <div className="mt-4 p-3 bg-green-50 border border-green-200 rounded-lg">
              <p className="text-green-800">
                <strong>Auto-calculated Total:</strong> ₹{newItem.total.toFixed(2)}
                ({newItem.quantity} × ₹{newItem.unitPrice.toFixed(2)})
              </p>
            </div>
          )}
        </div>

        {/* Test Items Table */}
        <div className="mb-6">
          <h2 className="text-lg font-semibold mb-4">Test Bill Items</h2>
          <div className="overflow-x-auto">
            <table className="w-full border-collapse">
              <thead>
                <tr className="bg-gray-50">
                  <th className="border border-gray-200 px-4 py-2 text-left">Service</th>
                  <th className="border border-gray-200 px-4 py-2 text-left">Sub-Service</th>
                  <th className="border border-gray-200 px-4 py-2 text-center">Quantity</th>
                  <th className="border border-gray-200 px-4 py-2 text-right">Unit Price</th>
                  <th className="border border-gray-200 px-4 py-2 text-right">Total</th>
                  <th className="border border-gray-200 px-4 py-2 text-center">Actions</th>
                </tr>
              </thead>
              <tbody>
                {testItems.map((item) => (
                  <tr key={item.id} className="hover:bg-gray-50">
                    <td className="border border-gray-200 px-4 py-2">{item.serviceName}</td>
                    <td className="border border-gray-200 px-4 py-2">{item.subServiceName}</td>
                    <td className="border border-gray-200 px-4 py-2 text-center">{item.quantity}</td>
                    <td className="border border-gray-200 px-4 py-2 text-right">₹{item.unitPrice.toFixed(2)}</td>
                    <td className="border border-gray-200 px-4 py-2 text-right font-medium">₹{item.total.toFixed(2)}</td>
                    <td className="border border-gray-200 px-4 py-2 text-center">
                      <button
                        onClick={() => removeItem(item.id)}
                        className="text-red-600 hover:text-red-900"
                      >
                        <Trash2 className="h-4 w-4" />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

        {/* Totals */}
        <div className="bg-gray-50 rounded-lg p-4">
          <h2 className="text-lg font-semibold mb-4">Bill Totals</h2>
          <div className="space-y-2">
            <div className="flex justify-between">
              <span>Subtotal:</span>
              <span className="font-medium">₹{totals.subtotal.toFixed(2)}</span>
            </div>
            <div className="flex justify-between">
              <span>Service Charges:</span>
              <span className="font-medium">₹{totals.serviceCharges.toFixed(2)}</span>
            </div>
            <div className="flex justify-between">
              <span>Discount:</span>
              <span className="font-medium">-₹{totals.discount.toFixed(2)}</span>
            </div>
            <div className="border-t pt-2 flex justify-between text-lg font-bold">
              <span>Grand Total:</span>
              <span className="text-blue-600">₹{totals.grandTotal.toFixed(2)}</span>
            </div>
          </div>
        </div>

        {/* Test Results */}
        <div className="mt-6 p-4 bg-blue-50 border border-blue-200 rounded-lg">
          <div className="flex items-center gap-2 mb-2">
            <CheckCircle className="h-5 w-5 text-blue-600" />
            <h3 className="font-semibold text-blue-800">Test Results</h3>
          </div>
          <ul className="text-sm text-blue-700 space-y-1">
            <li>✅ Price auto-population when sub-service selected</li>
            <li>✅ Automatic amount calculation (quantity × price)</li>
            <li>✅ Real-time total updates</li>
            <li>✅ Special pricing rules (Pan: ₹300, Aadhaar: ₹500)</li>
            <li>✅ Grand total calculation with charges</li>
          </ul>
        </div>
      </div>
    </div>
  )
}

export default BillingTest
