import { useState, useEffect } from 'react'
import { format } from 'date-fns'
import toast from 'react-hot-toast'
import { 
  Plus, 
  Edit2, 
  Trash2, 
  Search,
  Filter,
  Calendar,
  Wrench,
  AlertTriangle,
  Printer,
  FileText,
  BarChart3,
  Clock,
  DollarSign,
  CheckCircle
} from 'lucide-react'
import { maintenanceAPI, machinesAPI } from '../services/api'
import { useNavigate } from 'react-router-dom'

const MachinesMaintenance = () => {
  const navigate = useNavigate()
  const [maintenance, setMaintenance] = useState([])
  const [machines, setMachines] = useState([])
  const [loading, setLoading] = useState(true)
  const [showModal, setShowModal] = useState(false)
  const [editingRecord, setEditingRecord] = useState(null)
  const [searchTerm, setSearchTerm] = useState('')
  const [filterMachine, setFilterMachine] = useState('')
  const [filterStatus, setFilterStatus] = useState('')
  const [filterStartDate, setFilterStartDate] = useState('')
  const [filterEndDate, setFilterEndDate] = useState('')

  const [formData, setFormData] = useState({
    machineId: '',
    serviceType: 'Routine Service',
    serviceDate: format(new Date(), 'yyyy-MM-dd'),
    nextServiceDate: '',
    cost: '',
    notes: '',
    status: 'Scheduled'
  })

  useEffect(() => {
    fetchData()
  }, [])

  const fetchData = async () => {
    try {
      const [maintenanceResponse, machinesResponse] = await Promise.all([
        maintenanceAPI.getAll(),
        machinesAPI.getAll()
      ])
      setMaintenance(maintenanceResponse.data)
      setMachines(machinesResponse.data)
    } catch (error) {
      toast.error('Failed to fetch maintenance data')
      console.error('Maintenance error:', error)
    } finally {
      setLoading(false)
    }
  }

  const handleSubmit = async (e) => {
    e.preventDefault()
    try {
      if (editingRecord) {
        await maintenanceAPI.update(editingRecord._id, formData)
        toast.success('Maintenance record updated successfully')
      } else {
        await maintenanceAPI.create(formData)
        toast.success('Maintenance scheduled successfully')
      }
      fetchData()
      resetForm()
    } catch (error) {
      toast.error('Failed to save maintenance record')
      console.error('Save maintenance error:', error)
    }
  }

  const handleEdit = (record) => {
    setEditingRecord(record)
    setFormData({
      machineId: record.machineId._id,
      serviceType: record.serviceType,
      serviceDate: format(new Date(record.serviceDate), 'yyyy-MM-dd'),
      nextServiceDate: record.nextServiceDate ? format(new Date(record.nextServiceDate), 'yyyy-MM-dd') : '',
      cost: record.cost || '',
      notes: record.notes || '',
      status: record.status
    })
    setShowModal(true)
  }

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this maintenance record?')) {
      try {
        await maintenanceAPI.delete(id)
        toast.success('Maintenance record deleted successfully')
        fetchData()
      } catch (error) {
        toast.error('Failed to delete maintenance record')
        console.error('Delete maintenance error:', error)
      }
    }
  }

  const resetForm = () => {
    setFormData({
      machineId: '',
      serviceType: 'Routine Service',
      serviceDate: format(new Date(), 'yyyy-MM-dd'),
      nextServiceDate: '',
      cost: '',
      notes: '',
      status: 'Scheduled'
    })
    setEditingRecord(null)
    setShowModal(false)
  }

  const filteredMaintenance = maintenance.filter(record => {
    const matchesSearch = record.machineId.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         record.serviceType.toLowerCase().includes(searchTerm.toLowerCase())
    const matchesMachine = !filterMachine || record.machineId._id === filterMachine
    const matchesStatus = !filterStatus || record.status === filterStatus
    const matchesStartDate = !filterStartDate || new Date(record.serviceDate) >= new Date(filterStartDate)
    const matchesEndDate = !filterEndDate || new Date(record.serviceDate) <= new Date(filterEndDate)
    
    return matchesSearch && matchesMachine && matchesStatus && matchesStartDate && matchesEndDate
  })

  const getStatusColor = (status) => {
    switch (status) {
      case 'Completed':
        return 'bg-green-100 text-green-800'
      case 'In Progress':
        return 'bg-blue-100 text-blue-800'
      case 'Scheduled':
        return 'bg-yellow-100 text-yellow-800'
      case 'Cancelled':
        return 'bg-red-100 text-red-800'
      default:
        return 'bg-gray-100 text-gray-800'
    }
  }

  const getPriorityColor = (nextServiceDate) => {
    if (!nextServiceDate) return 'bg-gray-100 text-gray-800'
    
    const daysUntil = Math.ceil((new Date(nextServiceDate) - new Date()) / (1000 * 60 * 60 * 24))
    
    if (daysUntil <= 7) return 'bg-red-100 text-red-800'
    if (daysUntil <= 30) return 'bg-yellow-100 text-yellow-800'
    return 'bg-green-100 text-green-800'
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
      </div>
    )
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-gray-900">Machines Maintenance</h2>
        <button
          onClick={() => setShowModal(true)}
          className="btn-primary flex items-center space-x-2"
        >
          <Plus className="h-4 w-4" />
          <span>Schedule Maintenance</span>
        </button>
      </div>

      {/* Quick Actions */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <button
          onClick={() => navigate('/machines?action=add')}
          className="bg-gradient-to-br from-blue-500 to-blue-600 border-l-4 border-blue-700 rounded-xl shadow-lg hover:shadow-xl transition-all duration-300 transform hover:-translate-y-1 p-6 text-white group"
        >
          <div className="flex flex-col items-center space-y-3">
            <div className="p-3 bg-white/20 rounded-full group-hover:bg-white/30 transition-colors">
              <Printer className="h-8 w-8 text-white" />
            </div>
            <div className="text-center">
              <h4 className="text-lg font-bold">Add Machine</h4>
              <p className="text-sm text-blue-100 opacity-90">Register new equipment</p>
            </div>
          </div>
        </button>

        <button
          onClick={() => navigate('/readings')}
          className="bg-gradient-to-br from-green-500 to-green-600 border-l-4 border-green-700 rounded-xl shadow-lg hover:shadow-xl transition-all duration-300 transform hover:-translate-y-1 p-6 text-white group"
        >
          <div className="flex flex-col items-center space-y-3">
            <div className="p-3 bg-white/20 rounded-full group-hover:bg-white/30 transition-colors">
              <FileText className="h-8 w-8 text-white" />
            </div>
            <div className="text-center">
              <h4 className="text-lg font-bold">Add Reading</h4>
              <p className="text-sm text-green-100 opacity-90">Record daily meter</p>
            </div>
          </div>
        </button>

        <button
          onClick={() => setShowModal(true)}
          className="bg-gradient-to-br from-orange-500 to-orange-600 border-l-4 border-orange-700 rounded-xl shadow-lg hover:shadow-xl transition-all duration-300 transform hover:-translate-y-1 p-6 text-white group"
        >
          <div className="flex flex-col items-center space-y-3">
            <div className="p-3 bg-white/20 rounded-full group-hover:bg-white/30 transition-colors">
              <Wrench className="h-8 w-8 text-white" />
            </div>
            <div className="text-center">
              <h4 className="text-lg font-bold">Schedule Maintenance</h4>
              <p className="text-sm text-orange-100 opacity-90">Plan service tasks</p>
            </div>
          </div>
        </button>

        <button
          onClick={() => navigate('/reports')}
          className="bg-gradient-to-br from-indigo-500 to-indigo-600 border-l-4 border-indigo-700 rounded-xl shadow-lg hover:shadow-xl transition-all duration-300 transform hover:-translate-y-1 p-6 text-white group"
        >
          <div className="flex flex-col items-center space-y-3">
            <div className="p-3 bg-white/20 rounded-full group-hover:bg-white/30 transition-colors">
              <BarChart3 className="h-8 w-8 text-white" />
            </div>
            <div className="text-center">
              <h4 className="text-lg font-bold">Reports</h4>
              <p className="text-sm text-indigo-100 opacity-90">View analytics</p>
            </div>
          </div>
        </button>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <div className="card bg-gradient-to-br from-blue-50 to-blue-100 border-l-4 border-blue-500">
          <div className="p-4">
            <div className="flex items-center">
              <div className="p-2 bg-blue-500 rounded-lg">
                <Wrench className="h-6 w-6 text-white" />
              </div>
              <div className="ml-4">
                <p className="text-sm font-medium text-blue-600">Total Maintenance</p>
                <p className="text-2xl font-bold text-blue-900">{maintenance.length}</p>
              </div>
            </div>
          </div>
        </div>

        <div className="card bg-gradient-to-br from-green-50 to-green-100 border-l-4 border-green-500">
          <div className="p-4">
            <div className="flex items-center">
              <div className="p-2 bg-green-500 rounded-lg">
                <CheckCircle className="h-6 w-6 text-white" />
              </div>
              <div className="ml-4">
                <p className="text-sm font-medium text-green-600">Completed</p>
                <p className="text-2xl font-bold text-green-900">
                  {maintenance.filter(r => r.status === 'Completed').length}
                </p>
              </div>
            </div>
          </div>
        </div>

        <div className="card bg-gradient-to-br from-yellow-50 to-yellow-100 border-l-4 border-yellow-500">
          <div className="p-4">
            <div className="flex items-center">
              <div className="p-2 bg-yellow-500 rounded-lg">
                <Clock className="h-6 w-6 text-white" />
              </div>
              <div className="ml-4">
                <p className="text-sm font-medium text-yellow-600">Scheduled</p>
                <p className="text-2xl font-bold text-yellow-900">
                  {maintenance.filter(r => r.status === 'Scheduled').length}
                </p>
              </div>
            </div>
          </div>
        </div>

        <div className="card bg-gradient-to-br from-purple-50 to-purple-100 border-l-4 border-purple-500">
          <div className="p-4">
            <div className="flex items-center">
              <div className="p-2 bg-purple-500 rounded-lg">
                <DollarSign className="h-6 w-6 text-white" />
              </div>
              <div className="ml-4">
                <p className="text-sm font-medium text-purple-600">Total Cost</p>
                <p className="text-2xl font-bold text-purple-900">
                  ₹{maintenance.reduce((sum, r) => sum + (r.cost || 0), 0).toFixed(2)}
                </p>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Filters */}
      <div className="card">
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Search
            </label>
            <div className="relative">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-gray-400" />
              <input
                type="text"
                placeholder="Search maintenance records..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="pl-10 w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-500"
              />
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Machine
            </label>
            <select
              value={filterMachine}
              onChange={(e) => setFilterMachine(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-500"
            >
              <option value="">All Machines</option>
              {machines.map((machine) => (
                <option key={machine._id} value={machine._id}>
                  {machine.name}
                </option>
              ))}
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Status
            </label>
            <select
              value={filterStatus}
              onChange={(e) => setFilterStatus(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-500"
            >
              <option value="">All Status</option>
              <option value="Scheduled">Scheduled</option>
              <option value="In Progress">In Progress</option>
              <option value="Completed">Completed</option>
              <option value="Cancelled">Cancelled</option>
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Start Date
            </label>
            <input
              type="date"
              value={filterStartDate}
              onChange={(e) => setFilterStartDate(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-500"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              End Date
            </label>
            <input
              type="date"
              value={filterEndDate}
              onChange={(e) => setFilterEndDate(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-500"
            />
          </div>
        </div>
      </div>

      {/* Maintenance Table */}
      <div className="card overflow-hidden">
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Machine
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Service Type
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Service Date
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Next Service
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Status
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Cost
                </th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                  Actions
                </th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {filteredMaintenance.length > 0 ? (
                filteredMaintenance.map((record) => (
                  <tr key={record._id} className="hover:bg-gray-50">
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex items-center">
                        <Printer className="h-5 w-5 text-gray-400 mr-3" />
                        <div className="text-sm font-medium text-gray-900">{record.machineId.name}</div>
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                      {record.serviceType}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                      <div className="flex items-center">
                        <Calendar className="h-4 w-4 text-gray-400 mr-2" />
                        {format(new Date(record.serviceDate), 'MMM dd, yyyy')}
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      {record.nextServiceDate ? (
                        <div className="flex items-center">
                          <Calendar className="h-4 w-4 text-gray-400 mr-2" />
                          <div>
                            <div className="text-sm text-gray-900">
                              {format(new Date(record.nextServiceDate), 'MMM dd, yyyy')}
                            </div>
                            <span className={`text-xs font-semibold px-2 py-1 rounded ${getPriorityColor(record.nextServiceDate)}`}>
                              {Math.ceil((new Date(record.nextServiceDate) - new Date()) / (1000 * 60 * 60 * 24))} days
                            </span>
                          </div>
                        </div>
                      ) : (
                        <span className="text-gray-400">Not set</span>
                      )}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <span className={`px-2 py-1 inline-flex text-xs leading-5 font-semibold rounded-full ${getStatusColor(record.status)}`}>
                        {record.status}
                      </span>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                      {record.cost ? `₹${record.cost}` : '-'}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium">
                      <div className="flex space-x-2">
                        <button
                          onClick={() => handleEdit(record)}
                          className="text-primary-600 hover:text-primary-900"
                        >
                          <Edit2 className="h-4 w-4" />
                        </button>
                        <button
                          onClick={() => handleDelete(record._id)}
                          className="text-red-600 hover:text-red-900"
                        >
                          <Trash2 className="h-4 w-4" />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan="7" className="px-6 py-4 text-center text-gray-500">
                    No maintenance records found
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Add/Edit Modal */}
      {showModal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 overflow-y-auto h-full w-full z-50 flex items-center justify-center p-4">
          <div className="relative bg-white rounded-xl shadow-2xl max-w-2xl w-full max-h-[90vh] overflow-y-auto">
            <div className="bg-gradient-to-r from-orange-500 to-orange-600 px-6 py-4 rounded-t-xl border-b border-orange-200">
              <div className="flex items-center justify-between">
                <h3 className="text-xl font-bold text-white flex items-center">
                  <Wrench className="h-6 w-6 mr-3" />
                  {editingRecord ? 'Edit Maintenance' : 'Schedule New Maintenance'}
                </h3>
                <button
                  onClick={resetForm}
                  className="text-white hover:text-orange-200 transition-colors"
                >
                  <svg className="h-6 w-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                  </svg>
                </button>
              </div>
            </div>
            
            <form onSubmit={handleSubmit} className="p-6 space-y-4">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Machine *
                  </label>
                  <select
                    value={formData.machineId}
                    onChange={(e) => setFormData({ ...formData, machineId: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-orange-500"
                    required
                  >
                    <option value="">Select a machine</option>
                    {machines.map((machine) => (
                      <option key={machine._id} value={machine._id}>
                        {machine.name} ({machine.brand} {machine.modelNumber})
                      </option>
                    ))}
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Service Type *
                  </label>
                  <select
                    value={formData.serviceType}
                    onChange={(e) => setFormData({ ...formData, serviceType: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-orange-500"
                    required
                  >
                    <option value="Routine Service">Routine Service</option>
                    <option value="Repair">Repair</option>
                    <option value="Inspection">Inspection</option>
                    <option value="Parts Replacement">Parts Replacement</option>
                    <option value="Cleaning">Cleaning</option>
                    <option value="Calibration">Calibration</option>
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Service Date *
                  </label>
                  <input
                    type="date"
                    value={formData.serviceDate}
                    onChange={(e) => setFormData({ ...formData, serviceDate: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-orange-500"
                    required
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Next Service Date
                  </label>
                  <input
                    type="date"
                    value={formData.nextServiceDate}
                    onChange={(e) => setFormData({ ...formData, nextServiceDate: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-orange-500"
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Cost (₹)
                  </label>
                  <input
                    type="number"
                    step="0.01"
                    value={formData.cost}
                    onChange={(e) => setFormData({ ...formData, cost: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-orange-500"
                    placeholder="0.00"
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Status *
                  </label>
                  <select
                    value={formData.status}
                    onChange={(e) => setFormData({ ...formData, status: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-orange-500"
                    required
                  >
                    <option value="Scheduled">Scheduled</option>
                    <option value="In Progress">In Progress</option>
                    <option value="Completed">Completed</option>
                    <option value="Cancelled">Cancelled</option>
                  </select>
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Notes
                </label>
                <textarea
                  value={formData.notes}
                  onChange={(e) => setFormData({ ...formData, notes: e.target.value })}
                  rows={3}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-orange-500"
                  placeholder="Enter any additional notes or observations..."
                />
              </div>

              <div className="flex justify-end space-x-3 pt-4">
                <button
                  type="button"
                  onClick={resetForm}
                  className="px-4 py-2 text-sm font-medium text-gray-700 bg-gray-100 rounded-md hover:bg-gray-200"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  className="btn-primary"
                >
                  {editingRecord ? 'Update Maintenance' : 'Schedule Maintenance'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  )
}

export default MachinesMaintenance
