import React, { useState, useEffect } from 'react'

const SubServiceAPITest = () => {
  const [services, setServices] = useState([])
  const [subServices, setSubServices] = useState([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')

  useEffect(() => {
    testAPIs()
  }, [])

  const testAPIs = async () => {
    try {
      setLoading(true)
      setError('')
      
      const token = localStorage.getItem('authToken')
      console.log('Token available:', !!token)
      
      // Test Services API
      console.log('Testing Services API...')
      const servicesResponse = await fetch('http://localhost:5001/api/services', {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      })
      
      if (servicesResponse.ok) {
        const servicesData = await servicesResponse.json()
        console.log('Services API Response:', servicesData)
        setServices(Array.isArray(servicesData) ? servicesData : [])
      } else {
        const errorText = await servicesResponse.text()
        console.error('Services API Error:', errorText)
        setError(`Services API Error: ${servicesResponse.status} - ${errorText}`)
      }
      
      // Test SubServices API
      console.log('Testing SubServices API...')
      const subServicesResponse = await fetch('https://g2026-backend.onrender.com/api/subservices', {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      })
      
      if (subServicesResponse.ok) {
        const subServicesData = await subServicesResponse.json()
        console.log('SubServices API Response:', subServicesData)
        setSubServices(Array.isArray(subServicesData) ? subServicesData : [])
      } else {
        const errorText = await subServicesResponse.text()
        console.error('SubServices API Error:', errorText)
        if (!error) {
          setError(`SubServices API Error: ${subServicesResponse.status} - ${errorText}`)
        }
      }
      
    } catch (err) {
      console.error('API Test Error:', err)
      setError(err.message || 'API test failed')
    } finally {
      setLoading(false)
    }
  }

  return (
    <div className="p-6 max-w-4xl mx-auto">
      <div className="bg-white rounded-lg shadow-lg p-6">
        <h1 className="text-2xl font-bold text-gray-800 mb-6">SubService API Test</h1>
        
        {loading && (
          <div className="text-center py-8">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mx-auto"></div>
            <p className="mt-4 text-gray-600">Testing APIs...</p>
          </div>
        )}
        
        {error && (
          <div className="bg-red-50 border border-red-200 rounded-lg p-4 mb-6">
            <h3 className="text-red-800 font-semibold">Error:</h3>
            <p className="text-red-600">{error}</p>
            <button 
              onClick={testAPIs}
              className="mt-2 px-4 py-2 bg-red-600 text-white rounded hover:bg-red-700"
            >
              Retry
            </button>
          </div>
        )}
        
        {!loading && !error && (
          <div>
            <div className="mb-6 p-4 bg-green-50 border border-green-200 rounded-lg">
              <h3 className="text-green-800 font-semibold">✅ APIs Working!</h3>
              <p className="text-green-600">Services: {services.length} loaded</p>
              <p className="text-green-600">SubServices: {subServices.length} loaded</p>
            </div>
            
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <h3 className="text-lg font-semibold mb-3">Services ({services.length})</h3>
                <div className="space-y-2">
                  {services.map((service) => (
                    <div key={service._id} className="border border-gray-200 rounded p-3">
                      <h4 className="font-medium">{service.serviceName}</h4>
                      <p className="text-sm text-gray-600">{service.description}</p>
                      <p className="text-xs text-gray-500">ID: {service._id}</p>
                    </div>
                  ))}
                </div>
              </div>
              
              <div>
                <h3 className="text-lg font-semibold mb-3">SubServices ({subServices.length})</h3>
                <div className="space-y-2">
                  {subServices.map((subService) => (
                    <div key={subService._id} className="border border-gray-200 rounded p-3">
                      <h4 className="font-medium">{subService.subServiceName}</h4>
                      <p className="text-sm text-gray-600">Price: ₹{subService.price}</p>
                      <p className="text-sm text-gray-600">Unit: {subService.unit}</p>
                      <p className="text-xs text-gray-500">Service ID: {subService.serviceId}</p>
                      <p className="text-xs text-gray-500">Status: {subService.isActive ? 'Active' : 'Inactive'}</p>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  )
}

export default SubServiceAPITest
