// Shared services data for Billing component
import { useState, useEffect } from 'react'

// Create a simple service to fetch and cache services data
export const useServicesData = () => {
  const [services, setServices] = useState([])
  const [subServices, setSubServices] = useState([])
  const [loading, setLoading] = useState(true)

  // Fetch services data
  const fetchServicesData = async () => {
    try {
      const token = localStorage.getItem('authToken')
      const response = await fetch('http://localhost:5001/api/services', {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      })
      
      if (response.ok) {
        const data = await response.json()
        setServices(Array.isArray(data) ? data : [])
        console.log('Services data fetched from API:', data)
      } else {
        console.error('Failed to fetch services data')
      }
    } catch (err) {
      console.error('Error fetching services data:', err)
    }
  }

  // Fetch sub-services data
  const fetchSubServicesData = async () => {
    try {
      const token = localStorage.getItem('authToken')
      const response = await fetch('http://localhost:5001/api/subservices', {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      })
      
      if (response.ok) {
        const data = await response.json()
        setSubServices(Array.isArray(data) ? data : [])
        console.log('Sub-services data fetched from API:', data)
      } else {
        console.error('Failed to fetch sub-services data')
      }
    } catch (err) {
      console.error('Error fetching sub-services data:', err)
    }
  }

  // Load data on component mount
  useEffect(() => {
    const loadData = async () => {
      setLoading(true)
      await Promise.all([fetchServicesData(), fetchSubServicesData()])
      setLoading(false)
    }
    loadData()
  }, [])

  // Function to get sub-services for a specific service
  const getSubServicesForService = (serviceId) => {
    return subServices.filter(ss => {
      // Handle both populated serviceId (object) and non-populated (string)
      if (typeof ss.serviceId === 'object') {
        return ss.serviceId._id === serviceId
      }
      return ss.serviceId === serviceId
    })
  }

  // Return data and functions
  return {
    services,
    subServices,
    loading,
    getSubServicesForService,
    refetch: () => {
      setLoading(true)
      return Promise.all([fetchServicesData(), fetchSubServicesData()]).finally(() => setLoading(false))
    }
  }
}
