// Shared category data for use across components
export const defaultCategories = [
  { id: 1, name: 'Construction', description: 'Building materials and construction supplies', subcategories: ['Foundation', 'Structural', 'Concrete', 'Bricks', 'Cement'], materialCount: 45 },
  { id: 2, name: 'Finishing', description: 'Interior and exterior finishing materials', subcategories: ['Painting', 'Flooring', 'Ceiling', 'Doors', 'Windows'], materialCount: 32 },
  { id: 3, name: 'Raw Materials', description: 'Basic raw materials for construction', subcategories: ['Wood', 'Steel', 'Cement', 'Sand', 'Aggregates'], materialCount: 28 },
  { id: 4, name: 'Electrical', description: 'Electrical components and supplies', subcategories: ['Wiring', 'Lighting', 'Switches', 'Sockets', 'Circuit Breakers'], materialCount: 41 },
  { id: 5, name: 'Plumbing', description: 'Plumbing fixtures and supplies', subcategories: ['Pipes', 'Fittings', 'Valves', 'Taps', 'Drainage'], materialCount: 25 }
]

// Get categories from localStorage or use defaults
export const getCategories = () => {
  try {
    const stored = localStorage.getItem('categories')
    return stored ? JSON.parse(stored) : defaultCategories
  } catch (error) {
    console.error('Error loading categories:', error)
    return defaultCategories
  }
}

// Save categories to localStorage
export const saveCategories = (categories) => {
  try {
    localStorage.setItem('categories', JSON.stringify(categories))
  } catch (error) {
    console.error('Error saving categories:', error)
  }
}

// Get category names array
export const getCategoryNames = () => {
  const categories = getCategories()
  return categories.map(cat => cat.name)
}

// Get subcategories for a specific category
export const getSubcategories = (categoryName) => {
  const categories = getCategories()
  const category = categories.find(cat => cat.name === categoryName)
  return category ? category.subcategories : []
}

// Get category options for select dropdowns
export const getCategoryOptions = () => {
  const categories = getCategories()
  return categories.map(cat => ({
    value: cat.name,
    label: cat.name,
    description: cat.description
  }))
}
