import React, { useState, useEffect } from 'react'
import { customersAPI } from '../services/api'

const CustomerPhotoTest = () => {
  const [customers, setCustomers] = useState([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')

  useEffect(() => {
    testCustomersAPI()
  }, [])

  const testCustomersAPI = async () => {
    try {
      setLoading(true)
      setError('')
      
      console.log('Testing customers API...')
      const response = await fetch('https://g2026-backend.onrender.com/api/customers')
      console.log('API Response:', response)
      
      const data = await response.json()
      setCustomers(data || [])
      console.log('Customers loaded:', data?.length || 0)
    } catch (err) {
      console.error('API Error:', err)
      setError(err.message || 'Failed to load customers')
    } finally {
      setLoading(false)
    }
  }

  const getImageUrl = (photoPath) => {
    if (!photoPath) return null
    
    if (photoPath.startsWith('http')) {
      return photoPath
    }
    
    const baseUrl = window.location.origin.includes('localhost') ? 
      'http://localhost:5001' : window.location.origin
    return `${baseUrl}/uploads/${photoPath}`
  }

  return (
    <div className="p-6 max-w-4xl mx-auto">
      <div className="bg-white rounded-lg shadow-lg p-6">
        <h1 className="text-2xl font-bold text-gray-800 mb-6">Customer Photo Test</h1>
        
        {loading && (
          <div className="text-center py-8">
            <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mx-auto"></div>
            <p className="mt-4 text-gray-600">Loading customers...</p>
          </div>
        )}
        
        {error && (
          <div className="bg-red-50 border border-red-200 rounded-lg p-4 mb-6">
            <h3 className="text-red-800 font-semibold">Error:</h3>
            <p className="text-red-600">{error}</p>
            <button 
              onClick={testCustomersAPI}
              className="mt-2 px-4 py-2 bg-red-600 text-white rounded hover:bg-red-700"
            >
              Retry
            </button>
          </div>
        )}
        
        {!loading && !error && (
          <div>
            <div className="mb-4 p-4 bg-green-50 border border-green-200 rounded-lg">
              <h3 className="text-green-800 font-semibold">✅ API Working!</h3>
              <p className="text-green-600">Successfully loaded {customers.length} customers</p>
            </div>
            
            <div className="space-y-4">
              {customers.map((customer) => (
                <div key={customer._id} className="border border-gray-200 rounded-lg p-4">
                  <div className="flex items-center space-x-4">
                    {/* Photo Display */}
                    <div className="relative">
                      {customer.photo ? (
                        <>
                          <img 
                            src={getImageUrl(customer.photo)}
                            alt={customer.name}
                            className="h-16 w-16 rounded-full object-cover border-2 border-gray-300"
                            onError={(e) => {
                              console.error('Image failed to load:', getImageUrl(customer.photo))
                              e.target.style.display = 'none'
                              e.target.nextSibling.style.display = 'flex'
                            }}
                          />
                          <div 
                            className="h-16 w-16 rounded-full bg-gray-200 flex items-center justify-center border-2 border-gray-300"
                            style={{ display: 'none' }}
                          >
                            <span className="text-gray-500 text-xs">No Photo</span>
                          </div>
                        </>
                      ) : (
                        <div className="h-16 w-16 rounded-full bg-gray-200 flex items-center justify-center border-2 border-gray-300">
                          <span className="text-gray-500 text-xs">No Photo</span>
                        </div>
                      )}
                    </div>
                    
                    {/* Customer Info */}
                    <div className="flex-1">
                      <h3 className="font-semibold text-gray-800">{customer.name}</h3>
                      <p className="text-sm text-gray-600">ID: {customer.customerId}</p>
                      <p className="text-sm text-gray-600">Phone: {customer.cellNo}</p>
                      <p className="text-sm text-gray-600">Email: {customer.emailId}</p>
                      {customer.photo && (
                        <p className="text-xs text-blue-600 mt-1">
                          Photo: {customer.photo}
                        </p>
                      )}
                    </div>
                  </div>
                </div>
              ))}
            </div>
            
            {customers.length === 0 && (
              <div className="text-center py-8 text-gray-500">
                No customers found in the database.
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  )
}

export default CustomerPhotoTest
