import { useState, useEffect } from 'react'
import { useSearchParams } from 'react-router-dom'
import { Cog, Folder, TrendingUp, TrendingDown, Box, FolderOpen, Package } from 'lucide-react'
import Services from './Settings/Services'
import SubServices from './Settings/SubServices'
import ExpenseCategories from './Settings/ExpenseCategories'
import ExpenseSubCategories from './Settings/ExpenseSubCategories'
import Categories from './Settings/Categories'
import StockManagement from './Settings/StockManagement'

const Settings = () => {
  const [searchParams] = useSearchParams()
  const [activeTab, setActiveTab] = useState('services')

  useEffect(() => {
    const tab = searchParams.get('tab')
    if (tab) {
      setActiveTab(tab)
    }
  }, [searchParams])

  const tabs = [
    { id: 'services', name: 'Income-Services', icon: Package, type: 'income' },
    { id: 'subservices', name: 'Income-Sub-Services', icon: TrendingUp, type: 'income' },
    { id: 'expense-categories', name: 'Expense Categories', icon: Folder, type: 'expense' },
    { id: 'expense-subcategories', name: 'Expense Subcategories', icon: TrendingDown, type: 'expense' },
    { id: 'categories', name: 'Categories', icon: FolderOpen, type: 'neutral' },
    { id: 'stock-management', name: 'Stock Management', icon: Box, type: 'neutral' }
  ]

  const getTabClasses = (tab, isActive) => {
    const baseClasses = 'py-4 px-5 font-medium text-sm flex flex-col items-center space-y-2 transition-all duration-300 border-2 cursor-pointer'
    
    if (isActive) {
      if (tab.type === 'income') {
        return `${baseClasses} bg-gradient-to-br from-green-400 via-green-500 to-green-600 border-green-700 text-white shadow-xl shadow-green-500/30 transform -translate-y-2`
      } else if (tab.type === 'expense') {
        return `${baseClasses} bg-gradient-to-br from-red-400 via-red-500 to-red-600 border-red-700 text-white shadow-xl shadow-red-500/30 transform -translate-y-2`
      } else {
        return `${baseClasses} bg-gradient-to-br from-blue-400 via-blue-500 to-blue-600 border-blue-700 text-white shadow-xl shadow-blue-500/30 transform -translate-y-2`
      }
    } else {
      return `${baseClasses} bg-gradient-to-br from-gray-100 to-gray-200 border-gray-300 text-gray-700 hover:from-gray-200 hover:to-gray-300 hover:border-gray-400 hover:shadow-lg hover:-translate-y-1`
    }
  }

  const getTabIconColor = (tab, isActive) => {
    if (isActive) {
      return 'text-white'
    } else {
      return 'text-gray-500'
    }
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-50 to-gray-100 p-6">
    

      {/* Tab Navigation */}
      <div className="bg-white rounded-xl shadow-lg overflow-hidden border border-gray-200">
        <div className="bg-gradient-to-br from-gray-50 to-gray-100 p-6">
          <nav className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-4" aria-label="Tabs">
            {tabs.map((tab) => {
              const Icon = tab.icon
              const isActive = activeTab === tab.id
              return (
                <button
                  key={tab.id}
                  onClick={() => setActiveTab(tab.id)}
                  className={`${getTabClasses(tab, isActive)} rounded-xl`}
                >
                  <Icon className={`h-6 w-6 ${getTabIconColor(tab, isActive)}`} />
                  <span className="text-center text-xs font-medium">{tab.name}</span>
                  {tab.type === 'income' ? (
                    <TrendingUp className={`h-4 w-4 ${isActive ? 'text-white' : 'text-gray-400'}`} />
                  ) : tab.type === 'expense' ? (
                    <TrendingDown className={`h-4 w-4 ${isActive ? 'text-white' : 'text-gray-400'}`} />
                  ) : (
                    <Box className={`h-4 w-4 ${isActive ? 'text-white' : 'text-gray-400'}`} />
                  )}
                </button>
              )
            })}
          </nav>
        </div>

        {/* Tab Content */}
        <div className="p-6 bg-gradient-to-br from-white to-gray-50">
          <div className="bg-white rounded-lg shadow-inner p-6 border border-gray-100">
            {activeTab === 'services' && <Services />}
            {activeTab === 'subservices' && <SubServices />}
            {activeTab === 'expense-categories' && <ExpenseCategories />}
            {activeTab === 'expense-subcategories' && <ExpenseSubCategories />}
            {activeTab === 'categories' && <Categories />}
            {activeTab === 'stock-management' && <StockManagement />}
          </div>
        </div>
      </div>
    </div>
  )
}

export default Settings
