import { Routes, Route } from 'react-router-dom'
import Layout from './components/Layout'
import ErrorBoundary from './components/ErrorBoundary'
import AuthGuard from './components/AuthGuard'
import Login from './pages/Login'
import Dashboard from './pages/Dashboard'
import Customers from './pages/Customers'
import Machines from './pages/Maintance/Machines'
import MachinesMaintenance from './pages/MachinesMaintenance'
import Readings from './pages/Maintance/Readings'
import Maintenance from './pages/Maintance/Maintenance'
import Reports from './pages/Reports'
import Settings from './pages/Settings'
import Billing from './pages/Billing'
import BillingTest from './components/BillingTest'
import SeparateTableTest from './components/SeparateTableTest'
import SubCategoryPriceTest from './components/SubCategoryPriceTest'
import CustomerPhotoTest from './components/CustomerPhotoTest'
import SubServiceAPITest from './components/SubServiceAPITest'
import ExpensesManagement from './pages/ExpensesManagement'
import BalanceSheet from './pages/BalanceSheet'
import DailySalesExpenseReport from './pages/DailySalesExpenseReport'
import Reminder from './pages/Reminder'

function App() {
  return (
    <ErrorBoundary>
      <Routes>
        {/* Public Routes */}
        <Route path="/login" element={<Login />} />
          
        {/* Protected Routes */}
        <Route path="/*" element={
          <AuthGuard>
            <Layout>
              <Routes>
                <Route path="/" element={<Dashboard />} />
                <Route path="/customers" element={<Customers />} />
                <Route path="/machines" element={<Machines />} />
                <Route path="/machines-maintenance" element={<MachinesMaintenance />} />
                <Route path="/readings" element={<Readings />} />
                <Route path="/maintenance" element={<Maintenance />} />
                <Route path="/reports" element={<Reports />} />
                <Route path="/settings" element={<Settings />} />
                <Route path="/billing" element={<Billing />} />
                <Route path="/billing-test" element={<BillingTest />} />
                <Route path="/separate-table-test" element={<SeparateTableTest />} />
                <Route path="/subcategory-price-test" element={<SubCategoryPriceTest />} />
                <Route path="/customer-photo-test" element={<CustomerPhotoTest />} />
                <Route path="/subservice-api-test" element={<SubServiceAPITest />} />
                <Route path="/expenses-management" element={<ExpensesManagement />} />
                <Route path="/balance-sheet" element={<BalanceSheet />} />
                <Route path="/daily-sales-expense-report" element={<DailySalesExpenseReport />} />
                <Route path="/reminder" element={<Reminder />} />
                <Route path="*" element={<Dashboard />} />
              </Routes>
            </Layout>
          </AuthGuard>
        } />
      </Routes>
    </ErrorBoundary>
  )
}

export default App
