import React, { useState, useEffect, useRef } from 'react'
import { 
  Plus, 
  Download, 
  Printer, 
  Filter, 
  Search, 
  X, 
  Edit2, 
  Trash2, 
  DollarSign, 
  Calendar, 
  Tag, 
  CreditCard, 
  Banknote,
  CheckCircle,
  XCircle,
  Receipt,
  TrendingUp,
  TrendingDown,
  AlertCircle
} from 'lucide-react'

const ExpensesManagement = () => {
  // State Management
  const [expenses, setExpenses] = useState([])
  const [showExpenseModal, setShowExpenseModal] = useState(false)
  const [editingExpense, setEditingExpense] = useState(null)
  const [showFilterDropdown, setShowFilterDropdown] = useState(false)
  const [searchTerm, setSearchTerm] = useState('')
  const [filters, setFilters] = useState({
    dateRange: { start: '', end: '' },
    category: '',
    paymentMode: '',
    status: ''
  })
  const [showToast, setShowToast] = useState({ show: false, message: '', type: '' })
  const printRef = useRef()

  // Form State
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    billNumber: '',
    category: '',
    subCategory: '',
    items: [{ itemName: '', quantity: 1, price: 0, amount: 0, category: '', subCategory: '' }],
    discount: 0,
    paymentMode: 'cash',
    referenceNumber: '',
    status: 'unpaid',
    notes: ''
  })

  // Categories and Subcategories
  const categories = [
    { id: 'office', name: 'Office Supplies' },
    { id: 'travel', name: 'Travel & Transport' },
    { id: 'food', name: 'Food & Entertainment' },
    { id: 'utilities', name: 'Utilities' },
    { id: 'maintenance', name: 'Maintenance' },
    { id: 'other', name: 'Other' }
  ]

  const subCategories = {
    office: ['Stationery', 'Equipment', 'Software', 'Furniture'],
    travel: ['Fuel', 'Taxi', 'Flight', 'Hotel', 'Train'],
    food: ['Restaurant', 'Catering', 'Snacks', 'Groceries'],
    utilities: ['Electricity', 'Water', 'Internet', 'Phone'],
    maintenance: ['Repairs', 'Cleaning', 'Services'],
    other: ['Miscellaneous']
  }

  // Load data from localStorage on mount
  useEffect(() => {
    const savedExpenses = localStorage.getItem('expenses')
    if (savedExpenses) {
      setExpenses(JSON.parse(savedExpenses))
    }
    generateBillNumber()
  }, [])

  // Save to localStorage whenever expenses change
  useEffect(() => {
    localStorage.setItem('expenses', JSON.stringify(expenses))
  }, [expenses])

  // Generate Bill Number
  const generateBillNumber = () => {
    const lastExpense = expenses.length > 0 ? expenses[expenses.length - 1] : null
    const lastNumber = lastExpense ? parseInt(lastExpense.billNumber.split('-')[1]) : 0
    const newNumber = lastNumber + 1
    const billNumber = `EXP-${newNumber.toString().padStart(4, '0')}`
    setFormData(prev => ({ ...prev, billNumber }))
  }

  // Calculate Totals
  const calculateTotals = () => {
    const subtotal = formData.items.reduce((sum, item) => sum + (item.quantity * item.price), 0)
    const total = subtotal - formData.discount
    return { subtotal, total }
  }

  // Add Item Row
  const addItemRow = () => {
    setFormData(prev => ({
      ...prev,
      items: [...prev.items, { itemName: '', quantity: 1, price: 0, amount: 0, category: '', subCategory: '' }]
    }))
  }

  // Remove Item Row
  const removeItemRow = (index) => {
    setFormData(prev => ({
      ...prev,
      items: prev.items.filter((_, i) => i !== index)
    }))
  }

  // Update Item
  const updateItem = (index, field, value) => {
    const updatedItems = [...formData.items]
    updatedItems[index] = { ...updatedItems[index], [field]: value }
    
    // Auto-calculate amount
    if (field === 'quantity' || field === 'price') {
      updatedItems[index].amount = updatedItems[index].quantity * updatedItems[index].price
    }
    
    setFormData(prev => ({ ...prev, items: updatedItems }))
  }

  // Handle Category Change
  const handleCategoryChange = (category) => {
    setFormData(prev => ({
      ...prev,
      category,
      subCategory: '' // Reset subcategory when category changes
    }))
  }

  // Save Expense
  const saveExpense = () => {
    const { subtotal, total } = calculateTotals()
    const expenseData = {
      ...formData,
      subtotal,
      total,
      id: editingExpense ? editingExpense.id : Date.now(),
      createdAt: editingExpense ? editingExpense.createdAt : new Date().toISOString()
    }

    if (editingExpense) {
      setExpenses(prev => prev.map(exp => exp.id === editingExpense.id ? expenseData : exp))
      showToastMessage('Expense updated successfully!', 'success')
    } else {
      setExpenses(prev => [...prev, expenseData])
      showToastMessage('Expense added successfully!', 'success')
    }

    resetForm()
    setShowExpenseModal(false)
  }

  // Delete Expense
  const deleteExpense = (id) => {
    if (window.confirm('Are you sure you want to delete this expense?')) {
      setExpenses(prev => prev.filter(exp => exp.id !== id))
      showToastMessage('Expense deleted successfully!', 'success')
    }
  }

  // Edit Expense
  const editExpense = (expense) => {
    setFormData(expense)
    setEditingExpense(expense)
    setShowExpenseModal(true)
  }

  // Reset Form
  const resetForm = () => {
    setFormData({
      date: new Date().toISOString().split('T')[0],
      billNumber: '',
      category: '',
      subCategory: '',
      items: [{ itemName: '', quantity: 1, price: 0, amount: 0, category: '', subCategory: '' }],
      discount: 0,
      paymentMode: 'cash',
      referenceNumber: '',
      status: 'unpaid',
      notes: ''
    })
    setEditingExpense(null)
    generateBillNumber()
  }

  // Show Toast
  const showToastMessage = (message, type) => {
    setShowToast({ show: true, message, type })
    setTimeout(() => setShowToast({ show: false, message: '', type: '' }), 3000)
  }

  // Print Expense
  const printExpense = (expense) => {
    const printWindow = window.open('', '_blank')
    printWindow.document.write(`
      <html>
        <head>
          <title>Expense Bill - ${expense.billNumber}</title>
          <style>
            body { font-family: Arial, sans-serif; padding: 20px; }
            .header { text-align: center; margin-bottom: 30px; }
            .bill-info { display: flex; justify-content: space-between; margin-bottom: 20px; }
            .items-table { width: 100%; border-collapse: collapse; margin-bottom: 20px; }
            .items-table th, .items-table td { border: 1px solid #ddd; padding: 8px; text-align: left; }
            .items-table th { background-color: #f5f5f5; }
            .total-section { text-align: right; margin-top: 20px; }
            .status { padding: 5px 10px; border-radius: 4px; color: white; }
            .paid { background-color: #10b981; }
            .unpaid { background-color: #ef4444; }
            @media print { body { padding: 10px; } }
          </style>
        </head>
        <body>
          <div class="header">
            <h1>Expense Management System</h1>
            <h2>Expense Bill</h2>
          </div>
          <div class="bill-info">
            <div>
              <p><strong>Bill No:</strong> ${expense.billNumber}</p>
              <p><strong>Date:</strong> ${expense.date}</p>
              <p><strong>Category:</strong> ${expense.category}</p>
              ${expense.subCategory ? `<p><strong>Sub Category:</strong> ${expense.subCategory}</p>` : ''}
            </div>
            <div>
              <p><strong>Payment Mode:</strong> ${expense.paymentMode}</p>
              ${expense.referenceNumber ? `<p><strong>Reference:</strong> ${expense.referenceNumber}</p>` : ''}
              <p><strong>Status:</strong> <span class="status ${expense.status}">${expense.status.toUpperCase()}</span></p>
            </div>
          </div>
          <table class="items-table">
            <thead>
              <tr>
                <th>Item Name</th>
                <th>Quantity</th>
                <th>Price</th>
                <th>Amount</th>
              </tr>
            </thead>
            <tbody>
              ${expense.items.map(item => `
                <tr>
                  <td>${item.itemName}</td>
                  <td>${item.quantity}</td>
                  <td>₹${item.price.toFixed(2)}</td>
                  <td>₹${item.amount.toFixed(2)}</td>
                </tr>
              `).join('')}
            </tbody>
          </table>
          <div class="total-section">
            <p><strong>Subtotal:</strong> ₹${expense.subtotal.toFixed(2)}</p>
            <p><strong>Discount:</strong> ₹${expense.discount.toFixed(2)}</p>
            <p><strong>Total Amount:</strong> ₹${expense.total.toFixed(2)}</p>
          </div>
          ${expense.notes ? `<div><strong>Notes:</strong> ${expense.notes}</div>` : ''}
        </body>
      </html>
    `)
    printWindow.document.close()
    printWindow.print()
  }

  // Filter Expenses
  const filteredExpenses = expenses.filter(expense => {
    const matchesSearch = expense.billNumber.toLowerCase().includes(searchTerm.toLowerCase()) ||
                         expense.category.toLowerCase().includes(searchTerm.toLowerCase())
    
    const matchesCategory = !filters.category || expense.category === filters.category
    const matchesPaymentMode = !filters.paymentMode || expense.paymentMode === filters.paymentMode
    const matchesStatus = !filters.status || expense.status === filters.status
    
    let matchesDateRange = true
    if (filters.dateRange.start && filters.dateRange.end) {
      const expenseDate = new Date(expense.date)
      const startDate = new Date(filters.dateRange.start)
      const endDate = new Date(filters.dateRange.end)
      matchesDateRange = expenseDate >= startDate && expenseDate <= endDate
    }
    
    return matchesSearch && matchesCategory && matchesPaymentMode && matchesStatus && matchesDateRange
  })

  // Calculate Dashboard Stats
  const totalExpenses = expenses.reduce((sum, exp) => sum + exp.total, 0)
  const paidAmount = expenses.filter(exp => exp.status === 'paid').reduce((sum, exp) => sum + exp.total, 0)
  const unpaidAmount = expenses.filter(exp => exp.status === 'unpaid').reduce((sum, exp) => sum + exp.total, 0)
  const currentMonth = new Date().getMonth()
  const currentYear = new Date().getFullYear()
  const thisMonthExpenses = expenses
    .filter(exp => {
      const expDate = new Date(exp.date)
      return expDate.getMonth() === currentMonth && expDate.getFullYear() === currentYear
    })
    .reduce((sum, exp) => sum + exp.total, 0)

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Toast Notification */}
      {showToast.show && (
        <div className={`fixed top-4 right-4 z-50 px-6 py-3 rounded-lg shadow-lg ${
          showToast.type === 'success' ? 'bg-green-500' : 'bg-red-500'
        } text-white flex items-center gap-2`}>
          {showToast.type === 'success' ? <CheckCircle size={20} /> : <XCircle size={20} />}
          {showToast.message}
        </div>
      )}

      {/* Header */}
      <header className="bg-white shadow-sm border-b">
        <div className="w-full px-4 sm:px-6 lg:px-8 py-6">
          <div className="flex justify-between items-center">
            <div>
              <h1 className="text-3xl font-bold text-gray-900">Expenses Management</h1>
              <p className="text-gray-600 mt-1">Track and manage your business expenses</p>
            </div>
            <div className="flex gap-3">
              <button
                onClick={() => {
                  resetForm()
                  setShowExpenseModal(true)
                }}
                className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors"
              >
                <Plus size={20} />
                Add Expense
              </button>
              <button className="flex items-center gap-2 bg-green-600 text-white px-4 py-2 rounded-lg hover:bg-green-700 transition-colors">
                <Download size={20} />
                Export
              </button>
              <button className="flex items-center gap-2 bg-purple-600 text-white px-4 py-2 rounded-lg hover:bg-purple-700 transition-colors">
                <Printer size={20} />
                Print
              </button>
            </div>
          </div>
        </div>
      </header>

      {/* Dashboard Summary Cards */}
      <div className="w-full px-4 sm:px-6 lg:px-8 py-8">
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
          <div className="bg-white rounded-xl shadow-sm p-6 border border-gray-200">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-gray-600">Total Expenses</p>
                <p className="text-2xl font-bold text-gray-900">₹{totalExpenses.toFixed(2)}</p>
              </div>
              <div className="bg-blue-100 p-3 rounded-lg">
                <DollarSign className="text-blue-600" size={24} />
              </div>
            </div>
          </div>
          
          <div className="bg-white rounded-xl shadow-sm p-6 border border-gray-200">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-gray-600">Paid Amount</p>
                <p className="text-2xl font-bold text-green-600">₹{paidAmount.toFixed(2)}</p>
              </div>
              <div className="bg-green-100 p-3 rounded-lg">
                <CheckCircle className="text-green-600" size={24} />
              </div>
            </div>
          </div>
          
          <div className="bg-white rounded-xl shadow-sm p-6 border border-gray-200">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-gray-600">Unpaid Amount</p>
                <p className="text-2xl font-bold text-red-600">₹{unpaidAmount.toFixed(2)}</p>
              </div>
              <div className="bg-red-100 p-3 rounded-lg">
                <XCircle className="text-red-600" size={24} />
              </div>
            </div>
          </div>
          
          <div className="bg-white rounded-xl shadow-sm p-6 border border-gray-200">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-gray-600">This Month</p>
                <p className="text-2xl font-bold text-purple-600">₹{thisMonthExpenses.toFixed(2)}</p>
              </div>
              <div className="bg-purple-100 p-3 rounded-lg">
                <TrendingUp className="text-purple-600" size={24} />
              </div>
            </div>
          </div>
        </div>

        {/* Search and Filters */}
        <div className="bg-white rounded-xl shadow-sm p-6 border border-gray-200 mt-8">
          <div className="flex flex-col lg:flex-row gap-4">
            <div className="flex-1">
              <div className="relative">
                <Search className="absolute left-3 top-3 text-gray-400" size={20} />
                <input
                  type="text"
                  placeholder="Search by Bill No or Category..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                />
              </div>
            </div>
            
            <div className="relative">
              <button
                onClick={() => setShowFilterDropdown(!showFilterDropdown)}
                className="flex items-center gap-2 px-4 py-2 border border-gray-300 rounded-lg hover:bg-gray-50"
              >
                <Filter size={20} />
                Filters
              </button>
              
              {showFilterDropdown && (
                <div className="absolute right-0 mt-2 w-80 bg-white rounded-lg shadow-lg border border-gray-200 z-10 p-4">
                  <h3 className="font-semibold mb-3">Filter Expenses</h3>
                  
                  <div className="space-y-3">
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Date Range</label>
                      <div className="flex gap-2">
                        <input
                          type="date"
                          value={filters.dateRange.start}
                          onChange={(e) => setFilters(prev => ({ ...prev, dateRange: { ...prev.dateRange, start: e.target.value } }))}
                          className="flex-1 px-3 py-2 border border-gray-300 rounded-lg text-sm"
                        />
                        <input
                          type="date"
                          value={filters.dateRange.end}
                          onChange={(e) => setFilters(prev => ({ ...prev, dateRange: { ...prev.dateRange, end: e.target.value } }))}
                          className="flex-1 px-3 py-2 border border-gray-300 rounded-lg text-sm"
                        />
                      </div>
                    </div>
                    
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Category</label>
                      <select
                        value={filters.category}
                        onChange={(e) => setFilters(prev => ({ ...prev, category: e.target.value }))}
                        className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm"
                      >
                        <option value="">All Categories</option>
                        {categories.map(cat => (
                          <option key={cat.id} value={cat.id}>{cat.name}</option>
                        ))}
                      </select>
                    </div>
                    
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Payment Mode</label>
                      <select
                        value={filters.paymentMode}
                        onChange={(e) => setFilters(prev => ({ ...prev, paymentMode: e.target.value }))}
                        className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm"
                      >
                        <option value="">All Payment Modes</option>
                        <option value="cash">Cash</option>
                        <option value="upi">UPI</option>
                        <option value="bank">Bank Transfer</option>
                        <option value="card">Card</option>
                      </select>
                    </div>
                    
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Status</label>
                      <select
                        value={filters.status}
                        onChange={(e) => setFilters(prev => ({ ...prev, status: e.target.value }))}
                        className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm"
                      >
                        <option value="">All Status</option>
                        <option value="paid">Paid</option>
                        <option value="unpaid">Unpaid</option>
                      </select>
                    </div>
                    
                    <button
                      onClick={() => setFilters({ dateRange: { start: '', end: '' }, category: '', paymentMode: '', status: '' })}
                      className="w-full bg-gray-100 text-gray-700 px-3 py-2 rounded-lg hover:bg-gray-200 text-sm"
                    >
                      Clear Filters
                    </button>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Expenses Table */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 mt-8">
          <div className="p-6 border-b border-gray-200">
            <h2 className="text-lg font-semibold text-gray-900">Expense Records</h2>
          </div>
          
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="bg-gray-50">
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Date</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Bill No</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Category</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Sub Category</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Total Amount</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Payment Mode</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Reference No</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Status</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Actions</th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {filteredExpenses.map((expense) => (
                  <tr key={expense.id} className={expense.status === 'unpaid' ? 'bg-red-50' : ''}>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                      {new Date(expense.date).toLocaleDateString()}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">
                      {expense.billNumber}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                      {categories.find(cat => cat.id === expense.category)?.name || expense.category}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                      {expense.subCategory || '-'}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">
                      ₹{expense.total.toFixed(2)}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                      <div className="flex items-center gap-1">
                        {expense.paymentMode === 'cash' && <Banknote size={16} />}
                        {expense.paymentMode === 'upi' && <CreditCard size={16} />}
                        {expense.paymentMode === 'bank' && <CreditCard size={16} />}
                        {expense.paymentMode === 'card' && <CreditCard size={16} />}
                        {expense.paymentMode.charAt(0).toUpperCase() + expense.paymentMode.slice(1)}
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                      {expense.referenceNumber || '-'}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <span className={`px-2 py-1 text-xs rounded-full font-medium ${
                        expense.status === 'paid' 
                          ? 'bg-green-100 text-green-800' 
                          : 'bg-red-100 text-red-800'
                      }`}>
                        {expense.status.charAt(0).toUpperCase() + expense.status.slice(1)}
                      </span>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                      <div className="flex gap-2">
                        <button
                          onClick={() => editExpense(expense)}
                          className="text-blue-600 hover:text-blue-800"
                          title="Edit"
                        >
                          <Edit2 size={16} />
                        </button>
                        <button
                          onClick={() => deleteExpense(expense.id)}
                          className="text-red-600 hover:text-red-800"
                          title="Delete"
                        >
                          <Trash2 size={16} />
                        </button>
                        <button
                          onClick={() => printExpense(expense)}
                          className="text-purple-600 hover:text-purple-800"
                          title="Print"
                        >
                          <Printer size={16} />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
            
            {filteredExpenses.length === 0 && (
              <div className="text-center py-8">
                <Receipt className="mx-auto text-gray-400" size={48} />
                <p className="mt-2 text-gray-500">No expenses found</p>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Expense Modal */}
      {showExpenseModal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-xl shadow-xl w-full max-w-5xl max-h-[90vh] overflow-y-auto">
            <div className="p-6 border-b border-gray-200">
              <div className="flex justify-between items-center">
                <h2 className="text-2xl font-bold text-gray-900">
                  {editingExpense ? 'Edit Expense' : 'Add New Expense'}
                </h2>
                <button
                  onClick={() => {
                    setShowExpenseModal(false)
                    resetForm()
                  }}
                  className="text-gray-400 hover:text-gray-600"
                >
                  <X size={24} />
                </button>
              </div>
            </div>

            <div className="p-6 space-y-6">
              {/* Basic Details */}
              <div>
                <h3 className="text-lg font-semibold text-gray-900 mb-4">Basic Details</h3>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Date</label>
                    <input
                      type="date"
                      value={formData.date}
                      onChange={(e) => setFormData(prev => ({ ...prev, date: e.target.value }))}
                      className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Bill Number</label>
                    <input
                      type="text"
                      value={formData.billNumber}
                      onChange={(e) => setFormData(prev => ({ ...prev, billNumber: e.target.value }))}
                      className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                    />
                  </div>
                </div>
              </div>

              {/* Bill Particulars */}
              <div>
                <div className="flex justify-between items-center mb-3">
                  <h3 className="text-lg font-semibold text-gray-800">Bill Particulars</h3>
                  <button
                    onClick={addItemRow}
                    className="flex items-center gap-2 bg-green-600 text-white px-3 py-1.5 rounded-lg hover:bg-green-700 transition-colors"
                  >
                    <Plus size={16} />
                    Add Item
                  </button>
                </div>

                <div className="overflow-x-auto">
                  <table className="w-full border-collapse border border-gray-300">
                    <thead>
                      <tr className="bg-gray-100">
                        <th className="border border-gray-300 px-3 py-2 text-left text-sm font-medium">S.No</th>
                        <th className="border border-gray-300 px-3 py-2 text-left text-sm font-medium">Category</th>
                        <th className="border border-gray-300 px-3 py-2 text-left text-sm font-medium">Sub Category</th>
                        <th className="border border-gray-300 px-3 py-2 text-left text-sm font-medium">Item Name</th>
                        <th className="border border-gray-300 px-3 py-2 text-center text-sm font-medium">Qty</th>
                        <th className="border border-gray-300 px-3 py-2 text-right text-sm font-medium">Price</th>
                        <th className="border border-gray-300 px-3 py-2 text-right text-sm font-medium">Total</th>
                        <th className="border border-gray-300 px-3 py-2 text-center text-sm font-medium">Action</th>
                      </tr>
                    </thead>
                    <tbody>
                      {formData.items.map((item, index) => (
                        <tr key={index}>
                          <td className="border border-gray-300 px-3 py-2 text-center">{index + 1}</td>
                          <td className="border border-gray-300 px-3 py-2">
                            <select
                              value={item.category || ''}
                              onChange={(e) => updateItem(index, 'category', e.target.value)}
                              className="w-full border border-gray-200 rounded px-2 py-1 text-sm"
                            >
                              <option value="">Select Category</option>
                              {categories.map(cat => (
                                <option key={cat.id} value={cat.id}>{cat.name}</option>
                              ))}
                            </select>
                          </td>
                          <td className="border border-gray-300 px-3 py-2">
                            <select
                              value={item.subCategory || ''}
                              onChange={(e) => updateItem(index, 'subCategory', e.target.value)}
                              disabled={!item.category}
                              className="w-full border border-gray-200 rounded px-2 py-1 text-sm disabled:bg-gray-100"
                            >
                              <option value="">Select Sub Category</option>
                              {item.category && subCategories[item.category]?.map(sub => (
                                <option key={sub} value={sub}>{sub}</option>
                              ))}
                            </select>
                          </td>
                          <td className="border border-gray-300 px-3 py-2">
                            <input
                              type="text"
                              value={item.itemName}
                              onChange={(e) => updateItem(index, 'itemName', e.target.value)}
                              className="w-full border border-gray-200 rounded px-2 py-1 text-sm"
                              placeholder="Enter item name"
                            />
                          </td>
                          <td className="border border-gray-300 px-3 py-2">
                            <input
                              type="number"
                              min="1"
                              value={item.quantity}
                              onChange={(e) => updateItem(index, 'quantity', parseInt(e.target.value) || 1)}
                              className="w-full border border-gray-200 rounded px-2 py-1 text-center text-sm"
                            />
                          </td>
                          <td className="border border-gray-300 px-3 py-2">
                            <input
                              type="number"
                              min="0"
                              step="0.01"
                              value={item.price}
                              onChange={(e) => updateItem(index, 'price', parseFloat(e.target.value) || 0)}
                              className="w-full border border-gray-200 rounded px-2 py-1 text-right text-sm"
                            />
                          </td>
                          <td className="border border-gray-300 px-3 py-2 text-right font-medium">
                            {item.amount.toFixed(2)}
                          </td>
                          <td className="border border-gray-300 px-3 py-2 text-center">
                            <button
                              onClick={() => removeItemRow(index)}
                              className="text-red-600 hover:text-red-800 transition-colors"
                            >
                              <Trash2 size={16} />
                            </button>
                          </td>
                        </tr>
                      ))}
                      {formData.items.length === 0 && (
                        <tr>
                          <td colSpan="8" className="border border-gray-300 px-3 py-8 text-center text-gray-500">
                            No items added. Click "Add Item" to add items to the expense.
                          </td>
                        </tr>
                      )}
                    </tbody>
                  </table>
                </div>
              </div>

              {/* Payment and Calculation Section */}
              <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                {/* Payment Section - Left Side */}
                <div>
                  <h3 className="text-lg font-semibold text-gray-900 mb-4">Payment</h3>
                  <div className="space-y-4">
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Payment Mode</label>
                      <select
                        value={formData.paymentMode}
                        onChange={(e) => setFormData(prev => ({ ...prev, paymentMode: e.target.value, referenceNumber: '' }))}
                        className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                      >
                        <option value="cash">Cash Payment</option>
                        <option value="upi">UPI Payment</option>
                        <option value="phonepe">PhonePe</option>
                        <option value="paytm">Paytm</option>
                        <option value="googlepay">Google Pay</option>
                        <option value="debit">Debit Card</option>
                        <option value="credit">Credit Card</option>
                        <option value="netbanking">Net Banking</option>
                        <option value="bank">Bank Transfer</option>
                        <option value="cheque">Cheque</option>
                        <option value="emandate">E-Mandate</option>
                        <option value="wallet">Digital Wallet</option>
                      </select>
                    </div>
                    
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Reference Number</label>
                      <input
                        type="text"
                        value={formData.referenceNumber}
                        onChange={(e) => setFormData(prev => ({ ...prev, referenceNumber: e.target.value }))}
                        className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                        placeholder="Enter reference number"
                      />
                    </div>
                    
                    <div>
                      <label className="block text-sm font-medium text-gray-700 mb-1">Payment Status</label>
                      <select
                        value={formData.status}
                        onChange={(e) => setFormData(prev => ({ ...prev, status: e.target.value }))}
                        className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                      >
                        <option value="paid">Paid</option>
                        <option value="unpaid">Unpaid</option>
                        <option value="pending">Pending</option>
                        <option value="failed">Failed</option>
                        <option value="refunded">Refunded</option>
                      </select>
                    </div>
                  </div>
                </div>

                {/* Calculation Section - Right Side */}
                <div>
                  <h3 className="text-lg font-semibold text-gray-900 mb-4">Calculation</h3>
                  <div className="flex justify-end">
                    <div className="inline-flex flex-col space-y-2">
                      <div className="flex items-center justify-between px-4 py-2 bg-gray-100 rounded-lg min-w-[280px]">
                        <span className="text-sm font-medium text-gray-600">Subtotal</span>
                        <span className="text-lg font-bold text-gray-900">₹{calculateTotals().subtotal.toFixed(2)}</span>
                      </div>
                      
                      <div className="flex items-center justify-between px-4 py-2 bg-red-100 rounded-lg min-w-[280px]">
                        <span className="text-sm font-medium text-red-700">Discount</span>
                        <input
                          type="number"
                          min="0"
                          step="0.01"
                          value={formData.discount}
                          onChange={(e) => setFormData(prev => ({ ...prev, discount: parseFloat(e.target.value) || 0 }))}
                          className="w-28 px-2 py-1 border border-red-300 rounded bg-white text-right font-medium"
                        />
                      </div>
                      
                      <div className="flex items-center justify-between px-4 py-3 bg-gradient-to-r from-green-100 to-green-200 rounded-lg min-w-[280px] border border-green-300">
                        <span className="text-sm font-bold text-green-800">Total Amount</span>
                        <span className="text-xl font-bold text-green-700">₹{calculateTotals().total.toFixed(2)}</span>
                      </div>
                    </div>
                  </div>
                </div>
              </div>

              {/* Notes */}
              <div>
                <h3 className="text-lg font-semibold text-gray-900 mb-4">Notes</h3>
                <textarea
                  value={formData.notes}
                  onChange={(e) => setFormData(prev => ({ ...prev, notes: e.target.value }))}
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                  rows="3"
                  placeholder="Enter any additional notes..."
                />
              </div>

              {/* Action Buttons */}
              <div className="flex justify-end gap-3 pt-4 border-t">
                <button
                  onClick={() => {
                    setShowExpenseModal(false)
                    resetForm()
                  }}
                  className="px-6 py-2 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50"
                >
                  Cancel
                </button>
                <button
                  onClick={saveExpense}
                  className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700"
                >
                  {editingExpense ? 'Update Expense' : 'Save Expense'}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

export default ExpensesManagement
