import { useState, useEffect } from 'react'
import { toast } from 'react-hot-toast'
import { Plus, Search, Edit2, Trash2, Layers, ToggleLeft, ToggleRight } from 'lucide-react'

const ExpenseSubCategories = () => {
  const [subCategories, setSubCategories] = useState([])
  const [categories, setCategories] = useState([])
  const [loading, setLoading] = useState(true)
  const [searchTerm, setSearchTerm] = useState('')
  const [showForm, setShowForm] = useState(false)
  const [editingSubCategory, setEditingSubCategory] = useState(null)
  const [formData, setFormData] = useState({
    name: '',
    categoryId: '',
    isActive: true
  })

  useEffect(() => {
    fetchData()
  }, [])

  const fetchData = async () => {
    try {
      setLoading(true)
      
      // Fetch categories
      const storedCategories = localStorage.getItem('expenseCategories')
      if (storedCategories) {
        setCategories(JSON.parse(storedCategories))
      }

      // Fetch subcategories
      const storedSubCategories = localStorage.getItem('expenseSubCategories')
      if (storedSubCategories) {
        setSubCategories(JSON.parse(storedSubCategories))
      } else {
        // Default subcategories based on categories
        const defaultSubCategories = [
          // Office Supplies subcategories
          { id: 'stationery', name: 'Stationery', categoryId: 'office', isActive: true },
          { id: 'furniture', name: 'Furniture', categoryId: 'office', isActive: true },
          { id: 'electronics', name: 'Electronics', categoryId: 'office', isActive: true },
          
          // Maintenance subcategories
          { id: 'equipment', name: 'Equipment Repair', categoryId: 'maintenance', isActive: true },
          { id: 'building', name: 'Building Maintenance', categoryId: 'maintenance', isActive: true },
          { id: 'vehicle', name: 'Vehicle Maintenance', categoryId: 'maintenance', isActive: true },
          
          // Utilities subcategories
          { id: 'electricity', name: 'Electricity', categoryId: 'utilities', isActive: true },
          { id: 'water', name: 'Water', categoryId: 'utilities', isActive: true },
          { id: 'internet', name: 'Internet', categoryId: 'utilities', isActive: true },
          { id: 'phone', name: 'Phone', categoryId: 'utilities', isActive: true },
          
          // Travel subcategories
          { id: 'transport', name: 'Transportation', categoryId: 'travel', isActive: true },
          { id: 'accommodation', name: 'Accommodation', categoryId: 'travel', isActive: true },
          { id: 'food', name: 'Food & Meals', categoryId: 'travel', isActive: true },
          
          // Marketing subcategories
          { id: 'advertising', name: 'Advertising', categoryId: 'marketing', isActive: true },
          { id: 'events', name: 'Events', categoryId: 'marketing', isActive: true },
          { id: 'promotions', name: 'Promotions', categoryId: 'marketing', isActive: true },
          
          // Other expenses subcategories
          { id: 'miscellaneous', name: 'Miscellaneous', categoryId: 'other', isActive: true },
          { id: 'emergency', name: 'Emergency', categoryId: 'other', isActive: true }
        ]
        setSubCategories(defaultSubCategories)
        localStorage.setItem('expenseSubCategories', JSON.stringify(defaultSubCategories))
      }
    } catch (error) {
      toast.error('Failed to fetch data')
      console.error('Error fetching data:', error)
    } finally {
      setLoading(false)
    }
  }

  const handleSubmit = async (e) => {
    e.preventDefault()
    try {
      if (editingSubCategory) {
        const updatedSubCategories = subCategories.map(sub => 
          sub.id === editingSubCategory.id ? { ...formData, id: editingSubCategory.id } : sub
        )
        setSubCategories(updatedSubCategories)
        localStorage.setItem('expenseSubCategories', JSON.stringify(updatedSubCategories))
        toast.success('Subcategory updated successfully')
      } else {
        const newSubCategory = {
          ...formData,
          id: formData.name.toLowerCase().replace(/\s+/g, '_')
        }
        const updatedSubCategories = [...subCategories, newSubCategory]
        setSubCategories(updatedSubCategories)
        localStorage.setItem('expenseSubCategories', JSON.stringify(updatedSubCategories))
        toast.success('Subcategory created successfully')
      }
      resetForm()
    } catch (error) {
      toast.error('Failed to save subcategory')
      console.error('Error saving subcategory:', error)
    }
  }

  const resetForm = () => {
    setFormData({
      name: '',
      categoryId: '',
      isActive: true
    })
    setEditingSubCategory(null)
    setShowForm(false)
  }

  const handleEdit = (subCategory) => {
    setEditingSubCategory(subCategory)
    setFormData({
      name: subCategory.name,
      categoryId: subCategory.categoryId,
      isActive: subCategory.isActive
    })
    setShowForm(true)
  }

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this subcategory?')) {
      try {
        const updatedSubCategories = subCategories.filter(sub => sub.id !== id)
        setSubCategories(updatedSubCategories)
        localStorage.setItem('expenseSubCategories', JSON.stringify(updatedSubCategories))
        toast.success('Subcategory deleted successfully')
      } catch (error) {
        toast.error('Failed to delete subcategory')
        console.error('Error deleting subcategory:', error)
      }
    }
  }

  const toggleStatus = async (id) => {
    try {
      const updatedSubCategories = subCategories.map(sub => 
        sub.id === id ? { ...sub, isActive: !sub.isActive } : sub
      )
      setSubCategories(updatedSubCategories)
      localStorage.setItem('expenseSubCategories', JSON.stringify(updatedSubCategories))
      toast.success('Subcategory status updated successfully')
    } catch (error) {
      toast.error('Failed to update status')
      console.error('Error updating status:', error)
    }
  }

  const getCategoryName = (categoryId) => {
    const category = categories.find(cat => cat.id === categoryId)
    return category ? category.name : 'Unknown'
  }

  const filteredSubCategories = subCategories.filter(subCategory => {
    const categoryName = getCategoryName(subCategory.categoryId)
    return (
      subCategory.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      categoryName.toLowerCase().includes(searchTerm.toLowerCase())
    )
  })

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    )
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Expense Subcategories</h1>
          <p className="text-gray-600 mt-1">Manage expense subcategories for detailed tracking</p>
        </div>
        <button
          onClick={() => setShowForm(true)}
          className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors"
        >
          <Plus size={20} />
          Add Subcategory
        </button>
      </div>

      {/* Search */}
      <div className="bg-white rounded-lg shadow p-4">
        <div className="relative">
          <Search className="absolute left-3 top-3 text-gray-400" size={20} />
          <input
            type="text"
            placeholder="Search subcategories..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
          />
        </div>
      </div>

      {/* Subcategories Table */}
      <div className="bg-white rounded-lg shadow overflow-hidden">
        <table className="w-full">
          <thead className="bg-gray-50">
            <tr>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                Subcategory Name
              </th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                Category
              </th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">
                Status
              </th>
              <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">
                Actions
              </th>
            </tr>
          </thead>
          <tbody className="bg-white divide-y divide-gray-200">
            {filteredSubCategories.map((subCategory) => (
              <tr key={subCategory.id} className={!subCategory.isActive ? 'bg-gray-50' : ''}>
                <td className="px-6 py-4">
                  <div className="flex items-center gap-2">
                    <Layers size={20} className="text-purple-600" />
                    <span className="font-medium text-gray-900">{subCategory.name}</span>
                  </div>
                </td>
                <td className="px-6 py-4">
                  <span className="px-2 py-1 text-xs font-medium bg-blue-100 text-blue-800 rounded-full">
                    {getCategoryName(subCategory.categoryId)}
                  </span>
                </td>
                <td className="px-6 py-4">
                  <button
                    onClick={() => toggleStatus(subCategory.id)}
                    className={`flex items-center gap-2 px-3 py-1 rounded-full text-sm font-medium transition-colors ${
                      subCategory.isActive
                        ? 'bg-green-100 text-green-800 hover:bg-green-200'
                        : 'bg-red-100 text-red-800 hover:bg-red-200'
                    }`}
                  >
                    {subCategory.isActive ? (
                      <>
                        <ToggleRight size={16} />
                        Active
                      </>
                    ) : (
                      <>
                        <ToggleLeft size={16} />
                        Inactive
                      </>
                    )}
                  </button>
                </td>
                <td className="px-6 py-4 text-right">
                  <div className="flex justify-end gap-2">
                    <button
                      onClick={() => handleEdit(subCategory)}
                      className="text-blue-600 hover:text-blue-800 transition-colors"
                      title="Edit"
                    >
                      <Edit2 size={18} />
                    </button>
                    <button
                      onClick={() => handleDelete(subCategory.id)}
                      className="text-red-600 hover:text-red-800 transition-colors"
                      title="Delete"
                    >
                      <Trash2 size={18} />
                    </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        
        {filteredSubCategories.length === 0 && (
          <div className="text-center py-8">
            <Layers className="mx-auto text-gray-400" size={48} />
            <p className="mt-2 text-gray-500">No subcategories found</p>
          </div>
        )}
      </div>

      {/* Add/Edit Subcategory Modal */}
      {showForm && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-lg shadow-xl w-full max-w-md">
            <div className="p-6 border-b border-gray-200">
              <h2 className="text-xl font-bold text-gray-900">
                {editingSubCategory ? 'Edit Subcategory' : 'Add New Subcategory'}
              </h2>
            </div>
            
            <form onSubmit={handleSubmit} className="p-6 space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Category
                </label>
                <select
                  required
                  value={formData.categoryId}
                  onChange={(e) => setFormData({ ...formData, categoryId: e.target.value })}
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                >
                  <option value="">Select Category</option>
                  {categories.filter(cat => cat.isActive).map(category => (
                    <option key={category.id} value={category.id}>
                      {category.name}
                    </option>
                  ))}
                </select>
              </div>
              
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">
                  Subcategory Name
                </label>
                <input
                  type="text"
                  required
                  value={formData.name}
                  onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
                  placeholder="Enter subcategory name"
                />
              </div>
              
              <div className="flex items-center gap-3">
                <input
                  type="checkbox"
                  id="isActive"
                  checked={formData.isActive}
                  onChange={(e) => setFormData({ ...formData, isActive: e.target.checked })}
                  className="w-4 h-4 text-blue-600 border-gray-300 rounded focus:ring-blue-500"
                />
                <label htmlFor="isActive" className="text-sm font-medium text-gray-700">
                  Active
                </label>
              </div>
            </form>
            
            <div className="p-6 border-t border-gray-200 flex justify-end gap-3">
              <button
                onClick={resetForm}
                className="px-4 py-2 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 transition-colors"
              >
                Cancel
              </button>
              <button
                onClick={handleSubmit}
                className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors"
              >
                {editingSubCategory ? 'Update' : 'Save'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

export default ExpenseSubCategories
