import { useState, useEffect } from 'react'
import { format } from 'date-fns'
import toast from 'react-hot-toast'
import { 
  Download, 
  FileText, 
  Filter,
  Calendar,
  TrendingUp,
  Printer,
  DollarSign,
  BarChart3,
  Wrench
} from 'lucide-react'
import { readingsAPI, maintenanceAPI, machinesAPI, dashboardAPI } from '../services/api'
import { useNavigate } from 'react-router-dom'

const Reports = () => {
  const navigate = useNavigate()
  const [reportType, setReportType] = useState('full')
  const [machines, setMachines] = useState([])
  const [selectedMachine, setSelectedMachine] = useState('')
  const [startDate, setStartDate] = useState(format(new Date(Date.now() - 30 * 24 * 60 * 60 * 1000), 'yyyy-MM-dd'))
  const [endDate, setEndDate] = useState(format(new Date(), 'yyyy-MM-dd'))
  const [reportData, setReportData] = useState(null)
  const [loading, setLoading] = useState(false)

  useEffect(() => {
    fetchMachines()
  }, [])

  const fetchMachines = async () => {
    try {
      const response = await machinesAPI.getAll()
      setMachines(response.data)
    } catch (error) {
      toast.error('Failed to fetch machines')
      console.error('Machines error:', error)
    }
  }

  const generateReport = async () => {
    setLoading(true)
    try {
      const filters = {
        startDate,
        endDate
      }
      if (selectedMachine) {
        filters.machineId = selectedMachine
      }

      const [readingsResponse, maintenanceResponse, statsResponse] = await Promise.all([
        readingsAPI.getAll(filters),
        maintenanceAPI.getAll(filters),
        dashboardAPI.getReadingStats()
      ])

      const readings = readingsResponse.data
      const maintenance = maintenanceResponse.data
      const stats = statsResponse.data

      let processedData = {
        summary: {
          totalReadings: readings.length,
          totalMaintenance: maintenance.length,
          totalPrints: readings.reduce((sum, r) => sum + r.totalPrints, 0),
          totalCost: maintenance.reduce((sum, m) => sum + (parseFloat(m.cost) || 0), 0),
          avgPrintsPerDay: stats.avgPrintsPerDay || 0
        },
        readings: readings,
        maintenance: maintenance,
        machines: selectedMachine 
          ? machines.find(m => m._id === selectedMachine) 
          : machines,
        period: {
          start: startDate,
          end: endDate
        }
      }

      if (reportType === 'machine-wise') {
        processedData.machineBreakdown = machines.map(machine => {
          const machineReadings = readings.filter(r => r.machineId._id === machine._id)
          const machineMaintenance = maintenance.filter(m => m.machineId._id === machine._id)
          
          return {
            machine,
            totalReadings: machineReadings.length,
            totalPrints: machineReadings.reduce((sum, r) => sum + r.totalPrints, 0),
            totalMaintenance: machineMaintenance.length,
            totalCost: machineMaintenance.reduce((sum, m) => sum + (parseFloat(m.cost) || 0), 0)
          }
        }).filter(item => item.totalReadings > 0 || item.totalMaintenance > 0)
      }

      if (reportType === 'date-wise') {
        const dateMap = {}
        
        readings.forEach(reading => {
          const date = format(new Date(reading.date), 'yyyy-MM-dd')
          if (!dateMap[date]) {
            dateMap[date] = {
              date,
              totalReadings: 0,
              totalPrints: 0,
              totalMaintenance: 0,
              totalCost: 0
            }
          }
          dateMap[date].totalReadings++
          dateMap[date].totalPrints += reading.totalPrints
        })

        maintenance.forEach(record => {
          const date = format(new Date(record.serviceDate), 'yyyy-MM-dd')
          if (!dateMap[date]) {
            dateMap[date] = {
              date,
              totalReadings: 0,
              totalPrints: 0,
              totalMaintenance: 0,
              totalCost: 0
            }
          }
          dateMap[date].totalMaintenance++
          dateMap[date].totalCost += parseFloat(record.cost) || 0
        })

        processedData.dateBreakdown = Object.values(dateMap).sort((a, b) => 
          new Date(b.date) - new Date(a.date)
        )
      }

      setReportData(processedData)
    } catch (error) {
      toast.error('Failed to generate report')
      console.error('Report generation error:', error)
    } finally {
      setLoading(false)
    }
  }

  const exportToCSV = () => {
    if (!reportData) return

    let csvContent = ''
    let filename = ''

    if (reportType === 'full') {
      csvContent = 'Data Source,Machine Name,Date,Type,Details,Amount\n'
      
      reportData.readings.forEach(reading => {
        csvContent += `Reading,"${reading.machineId.name}",${format(new Date(reading.date), 'yyyy-MM-dd')},Print Count,"${reading.totalPrints} prints",\n`
      })
      
      reportData.maintenance.forEach(record => {
        csvContent += `Maintenance,"${record.machineId.name}",${format(new Date(record.serviceDate), 'yyyy-MM-dd')},"${record.serviceType}","${record.technicianName}",${record.cost || 0}\n`
      })
      
      filename = `maintenance_report_full_${format(new Date(), 'yyyy-MM-dd')}.csv`
    } else if (reportType === 'machine-wise' && reportData.machineBreakdown) {
      csvContent = 'Machine Name,Brand,Model,Total Readings,Total Prints,Total Maintenance,Total Cost\n'
      
      reportData.machineBreakdown.forEach(item => {
        csvContent += `"${item.machine.name}","${item.machine.brand}","${item.machine.modelNumber}",${item.totalReadings},${item.totalPrints},${item.totalMaintenance},${item.totalCost}\n`
      })
      
      filename = `maintenance_report_by_machine_${format(new Date(), 'yyyy-MM-dd')}.csv`
    } else if (reportType === 'date-wise' && reportData.dateBreakdown) {
      csvContent = 'Date,Total Readings,Total Prints,Total Maintenance,Total Cost\n'
      
      reportData.dateBreakdown.forEach(item => {
        csvContent += `${item.date},${item.totalReadings},${item.totalPrints},${item.totalMaintenance},${item.totalCost}\n`
      })
      
      filename = `maintenance_report_by_date_${format(new Date(), 'yyyy-MM-dd')}.csv`
    }

    const blob = new Blob([csvContent], { type: 'text/csv' })
    const url = window.URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = filename
    document.body.appendChild(a)
    a.click()
    document.body.removeChild(a)
    window.URL.revokeObjectURL(url)

    toast.success('Report exported successfully')
  }

  const exportToPDF = () => {
    // For PDF export, we'll create a simple HTML table and use window.print()
    if (!reportData) return

    const printWindow = window.open('', '_blank')
    const htmlContent = `
      <!DOCTYPE html>
      <html>
      <head>
        <title>Maintenance Report</title>
        <style>
          body { font-family: Arial, sans-serif; margin: 20px; }
          h1 { color: #2563eb; }
          table { border-collapse: collapse; width: 100%; margin: 20px 0; }
          th, td { border: 1px solid #ddd; padding: 8px; text-align: left; }
          th { background-color: #f2f2f2; }
          .summary { background-color: #f8f9fa; padding: 15px; border-radius: 5px; margin: 20px 0; }
        </style>
      </head>
      <body>
        <h1>Machinery Maintenance Report</h1>
        <p>Report Type: ${reportType}</p>
        <p>Period: ${format(new Date(startDate), 'MMM dd, yyyy')} - ${format(new Date(endDate), 'MMM dd, yyyy')}</p>
        
        <div class="summary">
          <h2>Summary</h2>
          <p>Total Readings: ${reportData.summary.totalReadings}</p>
          <p>Total Maintenance Records: ${reportData.summary.totalMaintenance}</p>
          <p>Total Prints: ${reportData.summary.totalPrints.toLocaleString()}</p>
          <p>Total Cost: ₹${reportData.summary.totalCost.toFixed(2)}</p>
          <p>Average Prints Per Day: ${Math.round(reportData.summary.avgPrintsPerDay)}</p>
        </div>
        
        ${reportType === 'full' ? `
          <h2>Readings</h2>
          <table>
            <tr><th>Date</th><th>Machine</th><th>Current Count</th><th>Total Prints</th></tr>
            ${reportData.readings.map(r => `
              <tr>
                <td>${format(new Date(r.date), 'MMM dd, yyyy')}</td>
                <td>${r.machineId.name}</td>
                <td>${r.currentCount.toLocaleString()}</td>
                <td>${r.totalPrints.toLocaleString()}</td>
              </tr>
            `).join('')}
          </table>
          
          <h2>Maintenance Records</h2>
          <table>
            <tr><th>Service Date</th><th>Machine</th><th>Service Type</th><th>Technician</th><th>Cost</th></tr>
            ${reportData.maintenance.map(m => `
              <tr>
                <td>${format(new Date(m.serviceDate), 'MMM dd, yyyy')}</td>
                <td>${m.machineId.name}</td>
                <td>${m.serviceType}</td>
                <td>${m.technicianName}</td>
                <td>₹${m.cost || 0}</td>
              </tr>
            `).join('')}
          </table>
        ` : ''}
        
        ${reportType === 'machine-wise' && reportData.machineBreakdown ? `
          <h2>Machine-wise Breakdown</h2>
          <table>
            <tr><th>Machine</th><th>Brand</th><th>Total Readings</th><th>Total Prints</th><th>Total Maintenance</th><th>Total Cost</th></tr>
            ${reportData.machineBreakdown.map(item => `
              <tr>
                <td>${item.machine.name}</td>
                <td>${item.machine.brand}</td>
                <td>${item.totalReadings}</td>
                <td>${item.totalPrints.toLocaleString()}</td>
                <td>${item.totalMaintenance}</td>
                <td>₹${item.totalCost.toFixed(2)}</td>
              </tr>
            `).join('')}
          </table>
        ` : ''}
        
        ${reportType === 'date-wise' && reportData.dateBreakdown ? `
          <h2>Date-wise Breakdown</h2>
          <table>
            <tr><th>Date</th><th>Total Readings</th><th>Total Prints</th><th>Total Maintenance</th><th>Total Cost</th></tr>
            ${reportData.dateBreakdown.map(item => `
              <tr>
                <td>${format(new Date(item.date), 'MMM dd, yyyy')}</td>
                <td>${item.totalReadings}</td>
                <td>${item.totalPrints.toLocaleString()}</td>
                <td>${item.totalMaintenance}</td>
                <td>₹${item.totalCost.toFixed(2)}</td>
              </tr>
            `).join('')}
          </table>
        ` : ''}
      </body>
      </html>
    `
    
    printWindow.document.write(htmlContent)
    printWindow.document.close()
    printWindow.focus()
    setTimeout(() => {
      printWindow.print()
      printWindow.close()
    }, 500)
    
    toast.success('PDF report generated for printing')
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-gray-900">Reports</h2>
        <div className="flex space-x-3">
          <button
            onClick={exportToCSV}
            disabled={!reportData}
            className="btn-secondary flex items-center space-x-2 disabled:opacity-50"
          >
            <Download className="h-4 w-4" />
            <span>Export CSV</span>
          </button>
          <button
            onClick={exportToPDF}
            disabled={!reportData}
            className="btn-primary flex items-center space-x-2 disabled:opacity-50"
          >
            <FileText className="h-4 w-4" />
            <span>Export PDF</span>
          </button>
        </div>
      </div>

      {/* Quick Actions */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <button
          onClick={() => navigate('/machines')}
          className="bg-gradient-to-br from-blue-500 to-blue-600 border-l-4 border-blue-700 rounded-xl shadow-lg hover:shadow-xl transition-all duration-300 transform hover:-translate-y-1 p-6 text-white group"
        >
          <div className="flex flex-col items-center space-y-3">
            <div className="p-3 bg-white/20 rounded-full group-hover:bg-white/30 transition-colors">
              <Printer className="h-8 w-8 text-white" />
            </div>
            <div className="text-center">
              <h4 className="text-lg font-bold">Add Machine</h4>
              <p className="text-sm text-blue-100 opacity-90">Register new equipment</p>
            </div>
          </div>
        </button>

        <button
          onClick={() => navigate('/readings')}
          className="bg-gradient-to-br from-green-500 to-green-600 border-l-4 border-green-700 rounded-xl shadow-lg hover:shadow-xl transition-all duration-300 transform hover:-translate-y-1 p-6 text-white group"
        >
          <div className="flex flex-col items-center space-y-3">
            <div className="p-3 bg-white/20 rounded-full group-hover:bg-white/30 transition-colors">
              <FileText className="h-8 w-8 text-white" />
            </div>
            <div className="text-center">
              <h4 className="text-lg font-bold">Add Reading</h4>
              <p className="text-sm text-green-100 opacity-90">Record daily meter</p>
            </div>
          </div>
        </button>

        <button
          onClick={() => navigate('/maintenance')}
          className="bg-gradient-to-br from-orange-500 to-orange-600 border-l-4 border-orange-700 rounded-xl shadow-lg hover:shadow-xl transition-all duration-300 transform hover:-translate-y-1 p-6 text-white group"
        >
          <div className="flex flex-col items-center space-y-3">
            <div className="p-3 bg-white/20 rounded-full group-hover:bg-white/30 transition-colors">
              <Wrench className="h-8 w-8 text-white" />
            </div>
            <div className="text-center">
              <h4 className="text-lg font-bold">Schedule Maintenance</h4>
              <p className="text-sm text-orange-100 opacity-90">Plan service tasks</p>
            </div>
          </div>
        </button>

        <button
          onClick={() => window.location.reload()}
          className="bg-gradient-to-br from-indigo-500 to-indigo-600 border-l-4 border-indigo-700 rounded-xl shadow-lg hover:shadow-xl transition-all duration-300 transform hover:-translate-y-1 p-6 text-white group"
        >
          <div className="flex flex-col items-center space-y-3">
            <div className="p-3 bg-white/20 rounded-full group-hover:bg-white/30 transition-colors">
              <BarChart3 className="h-8 w-8 text-white" />
            </div>
            <div className="text-center">
              <h4 className="text-lg font-bold">Refresh Reports</h4>
              <p className="text-sm text-indigo-100 opacity-90">Update analytics</p>
            </div>
          </div>
        </button>
      </div>

      {/* Report Configuration */}
      <div className="card">
        <h3 className="text-lg font-semibold text-gray-900 mb-4">Report Configuration</h3>
        
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Report Type
            </label>
            <select
              value={reportType}
              onChange={(e) => setReportType(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-500"
            >
              <option value="full">Full Report</option>
              <option value="machine-wise">Machine-wise</option>
              <option value="date-wise">Date-wise</option>
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Machine (Optional)
            </label>
            <select
              value={selectedMachine}
              onChange={(e) => setSelectedMachine(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-500"
            >
              <option value="">All Machines</option>
              {machines.map(machine => (
                <option key={machine._id} value={machine._id}>
                  {machine.name}
                </option>
              ))}
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Start Date
            </label>
            <input
              type="date"
              value={startDate}
              onChange={(e) => setStartDate(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-500"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              End Date
            </label>
            <input
              type="date"
              value={endDate}
              onChange={(e) => setEndDate(e.target.value)}
              className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-500"
            />
          </div>
        </div>

        <div className="mt-6">
          <button
            onClick={generateReport}
            disabled={loading}
            className="btn-primary flex items-center space-x-2 disabled:opacity-50"
          >
            <BarChart3 className="h-4 w-4" />
            <span>{loading ? 'Generating...' : 'Generate Report'}</span>
          </button>
        </div>
      </div>

      {/* Report Results */}
      {reportData && (
        <div className="space-y-6">
          {/* Summary Cards */}
          <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
            <div className="card">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-gray-600">Total Readings</p>
                  <p className="text-2xl font-bold text-gray-900">{reportData.summary.totalReadings}</p>
                </div>
                <div className="p-3 bg-primary-100 rounded-full">
                  <FileText className="h-6 w-6 text-primary-600" />
                </div>
              </div>
            </div>

            <div className="card">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-gray-600">Total Prints</p>
                  <p className="text-2xl font-bold text-gray-900">{reportData.summary.totalPrints.toLocaleString()}</p>
                </div>
                <div className="p-3 bg-green-100 rounded-full">
                  <TrendingUp className="h-6 w-6 text-green-600" />
                </div>
              </div>
            </div>

            <div className="card">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-gray-600">Maintenance Records</p>
                  <p className="text-2xl font-bold text-gray-900">{reportData.summary.totalMaintenance}</p>
                </div>
                <div className="p-3 bg-yellow-100 rounded-full">
                  <Printer className="h-6 w-6 text-yellow-600" />
                </div>
              </div>
            </div>

            <div className="card">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-gray-600">Total Cost</p>
                  <p className="text-2xl font-bold text-gray-900">₹{reportData.summary.totalCost.toFixed(2)}</p>
                </div>
                <div className="p-3 bg-secondary-100 rounded-full">
                  <DollarSign className="h-6 w-6 text-secondary-600" />
                </div>
              </div>
            </div>
          </div>

          {/* Detailed Tables */}
          {reportType === 'machine-wise' && reportData.machineBreakdown && (
            <div className="card">
              <h3 className="text-lg font-semibold text-gray-900 mb-4">Machine-wise Breakdown</h3>
              <div className="overflow-x-auto">
                <table className="min-w-full divide-y divide-gray-200">
                  <thead className="bg-gray-50">
                    <tr>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Machine</th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Brand</th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Total Readings</th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Total Prints</th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Maintenance</th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Total Cost</th>
                    </tr>
                  </thead>
                  <tbody className="bg-white divide-y divide-gray-200 table-zebra">
                    {reportData.machineBreakdown.map((item, index) => (
                      <tr key={index}>
                        <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">{item.machine.name}</td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{item.machine.brand}</td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{item.totalReadings}</td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{item.totalPrints.toLocaleString()}</td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{item.totalMaintenance}</td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">${item.totalCost.toFixed(2)}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {reportType === 'date-wise' && reportData.dateBreakdown && (
            <div className="card">
              <h3 className="text-lg font-semibold text-gray-900 mb-4">Date-wise Breakdown</h3>
              <div className="overflow-x-auto">
                <table className="min-w-full divide-y divide-gray-200">
                  <thead className="bg-gray-50">
                    <tr>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Date</th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Total Readings</th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Total Prints</th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Maintenance</th>
                      <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Total Cost</th>
                    </tr>
                  </thead>
                  <tbody className="bg-white divide-y divide-gray-200 table-zebra">
                    {reportData.dateBreakdown.map((item, index) => (
                      <tr key={index}>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                          {format(new Date(item.date), 'MMM dd, yyyy')}
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{item.totalReadings}</td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{item.totalPrints.toLocaleString()}</td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">{item.totalMaintenance}</td>
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">${item.totalCost.toFixed(2)}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  )
}

export default Reports
